<!DOCTYPE html>
<html lang="en">
<head>
  <meta charset="UTF-8" />
  <meta name="viewport" content="width=device-width, initial-scale=1.0"/>
  <title>REST API Design Review</title>
  <style>
    :root {
      --bg: #0f1117;
      --surface: #1a1d2e;
      --surface2: #252840;
      --border: #2e3150;
      --accent: #6c63ff;
      --accent2: #00d4aa;
      --danger: #ff4d6d;
      --warning: #ffb347;
      --success: #00d4aa;
      --text: #e8eaf6;
      --text-muted: #8b8fa8;
      --get: #61affe;
      --post: #49cc90;
      --put: #fca130;
      --delete: #f93e3e;
      --patch: #50e3c2;
    }

    * { box-sizing: border-box; margin: 0; padding: 0; }

    body {
      font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
      background: var(--bg);
      color: var(--text);
      min-height: 100vh;
      line-height: 1.6;
    }

    /* ── Header ── */
    header {
      background: linear-gradient(135deg, #1a1d2e 0%, #252840 50%, #1a1d2e 100%);
      border-bottom: 1px solid var(--border);
      padding: 2.5rem 2rem;
      text-align: center;
      position: relative;
      overflow: hidden;
    }
    header::before {
      content: '';
      position: absolute;
      inset: 0;
      background: radial-gradient(ellipse at 50% 0%, rgba(108,99,255,.25) 0%, transparent 70%);
      pointer-events: none;
    }
    header h1 {
      font-size: clamp(1.6rem, 4vw, 2.4rem);
      font-weight: 700;
      background: linear-gradient(135deg, #6c63ff, #00d4aa);
      -webkit-background-clip: text;
      -webkit-text-fill-color: transparent;
      background-clip: text;
      position: relative;
    }
    header p {
      color: var(--text-muted);
      margin-top: .5rem;
      font-size: .95rem;
      position: relative;
    }
    .badge-row {
      display: flex;
      justify-content: center;
      gap: .75rem;
      margin-top: 1.2rem;
      flex-wrap: wrap;
      position: relative;
    }
    .badge {
      padding: .3rem .85rem;
      border-radius: 999px;
      font-size: .75rem;
      font-weight: 600;
      letter-spacing: .04em;
      text-transform: uppercase;
    }
    .badge-issues  { background: rgba(255,77,109,.15); color: var(--danger);  border: 1px solid rgba(255,77,109,.3); }
    .badge-fixed   { background: rgba(0,212,170,.15);  color: var(--success); border: 1px solid rgba(0,212,170,.3); }
    .badge-version { background: rgba(108,99,255,.15); color: var(--accent);  border: 1px solid rgba(108,99,255,.3); }

    /* ── Layout ── */
    main {
      max-width: 1100px;
      margin: 0 auto;
      padding: 2rem 1.25rem 4rem;
    }

    /* ── Summary cards ── */
    .summary-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(200px, 1fr));
      gap: 1rem;
      margin-bottom: 2.5rem;
    }
    .summary-card {
      background: var(--surface);
      border: 1px solid var(--border);
      border-radius: 12px;
      padding: 1.25rem 1.5rem;
      display: flex;
      align-items: center;
      gap: 1rem;
      transition: transform .2s, box-shadow .2s;
    }
    .summary-card:hover {
      transform: translateY(-2px);
      box-shadow: 0 8px 24px rgba(0,0,0,.4);
    }
    .summary-icon {
      width: 46px; height: 46px;
      border-radius: 10px;
      display: flex; align-items: center; justify-content: center;
      font-size: 1.3rem;
      flex-shrink: 0;
    }
    .icon-danger  { background: rgba(255,77,109,.15);  color: var(--danger); }
    .icon-success { background: rgba(0,212,170,.15);   color: var(--success); }
    .icon-warning { background: rgba(255,179,71,.15);  color: var(--warning); }
    .icon-accent  { background: rgba(108,99,255,.15);  color: var(--accent); }
    .summary-label { font-size: .78rem; color: var(--text-muted); text-transform: uppercase; letter-spacing: .06em; }
    .summary-value { font-size: 1.6rem; font-weight: 700; line-height: 1.2; }

    /* ── Section headings ── */
    .section-title {
      font-size: 1.1rem;
      font-weight: 700;
      color: var(--text);
      margin-bottom: 1rem;
      padding-bottom: .5rem;
      border-bottom: 1px solid var(--border);
      display: flex;
      align-items: center;
      gap: .6rem;
    }
    .section-title span { color: var(--accent); }

    /* ── Principles strip ── */
    .principles {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(160px, 1fr));
      gap: .75rem;
      margin-bottom: 2.5rem;
    }
    .principle-pill {
      background: var(--surface);
      border: 1px solid var(--border);
      border-radius: 8px;
      padding: .75rem 1rem;
      font-size: .82rem;
      display: flex;
      align-items: flex-start;
      gap: .6rem;
    }
    .principle-pill .pi { font-size: 1.1rem; flex-shrink: 0; }
    .principle-pill strong { display: block; color: var(--accent2); margin-bottom: .15rem; }

    /* ── Endpoint cards ── */
    .endpoint-card {
      background: var(--surface);
      border: 1px solid var(--border);
      border-radius: 14px;
      margin-bottom: 1.25rem;
      overflow: hidden;
      transition: box-shadow .2s;
    }
    .endpoint-card:hover { box-shadow: 0 6px 20px rgba(0,0,0,.35); }

    .card-header {
      display: flex;
      align-items: center;
      gap: 1rem;
      padding: 1.1rem 1.4rem;
      cursor: pointer;
      user-select: none;
      transition: background .15s;
      flex-wrap: wrap;
    }
    .card-header:hover { background: rgba(255,255,255,.03); }

    .ep-number {
      width: 30px; height: 30px;
      border-radius: 50%;
      background: rgba(108,99,255,.2);
      color: var(--accent);
      font-size: .8rem;
      font-weight: 700;
      display: flex; align-items: center; justify-content: center;
      flex-shrink: 0;
    }

    .method-badge {
      padding: .28rem .75rem;
      border-radius: 6px;
      font-size: .78rem;
      font-weight: 700;
      letter-spacing: .05em;
      flex-shrink: 0;
      min-width: 62px;
      text-align: center;
    }
    .m-GET    { background: rgba(97,175,254,.15);  color: var(--get);    border: 1px solid rgba(97,175,254,.3); }
    .m-POST   { background: rgba(73,204,144,.15);  color: var(--post);   border: 1px solid rgba(73,204,144,.3); }
    .m-PUT    { background: rgba(252,161,48,.15);  color: var(--put);    border: 1px solid rgba(252,161,48,.3); }
    .m-DELETE { background: rgba(249,62,62,.15);   color: var(--delete); border: 1px solid rgba(249,62,62,.3); }
    .m-PATCH  { background: rgba(80,227,194,.15);  color: var(--patch);  border: 1px solid rgba(80,227,194,.3); }

    .ep-path {
      font-family: 'Cascadia Code', 'Fira Code', 'Courier New', monospace;
      font-size: .92rem;
      color: var(--text);
      flex: 1;
      min-width: 0;
      overflow: hidden;
      text-overflow: ellipsis;
      white-space: nowrap;
    }
    .ep-path.bad  { color: var(--danger);  text-decoration: line-through; opacity: .75; }
    .ep-path.good { color: var(--success); }

    .card-desc {
      font-size: .82rem;
      color: var(--text-muted);
      flex-shrink: 0;
      max-width: 200px;
      text-align: right;
    }

    .chevron {
      margin-left: auto;
      flex-shrink: 0;
      color: var(--text-muted);
      transition: transform .3s;
      font-size: 1rem;
    }
    .chevron.open { transform: rotate(180deg); }

    /* ── Card body ── */
    .card-body {
      display: none;
      padding: 0 1.4rem 1.4rem;
      border-top: 1px solid var(--border);
    }
    .card-body.open { display: block; }

    /* before / after */
    .compare-grid {
      display: grid;
      grid-template-columns: 1fr 1fr;
      gap: 1rem;
      margin: 1.1rem 0;
    }
    @media (max-width: 640px) { .compare-grid { grid-template-columns: 1fr; } }

    .compare-box {
      border-radius: 10px;
      padding: 1rem 1.1rem;
    }
    .compare-box.before {
      background: rgba(255,77,109,.07);
      border: 1px solid rgba(255,77,109,.25);
    }
    .compare-box.after {
      background: rgba(0,212,170,.07);
      border: 1px solid rgba(0,212,170,.25);
    }
    .compare-label {
      font-size: .7rem;
      font-weight: 700;
      letter-spacing: .1em;
      text-transform: uppercase;
      margin-bottom: .6rem;
      display: flex;
      align-items: center;
      gap: .4rem;
    }
    .compare-box.before .compare-label { color: var(--danger); }
    .compare-box.after  .compare-label { color: var(--success); }

    .code-line {
      font-family: 'Cascadia Code', 'Fira Code', monospace;
      font-size: .88rem;
      padding: .45rem .75rem;
      border-radius: 6px;
      background: rgba(0,0,0,.3);
      display: flex;
      align-items: center;
      gap: .6rem;
      margin-bottom: .4rem;
      flex-wrap: wrap;
    }

    /* issues list */
    .issues-list {
      list-style: none;
      margin: .8rem 0;
    }
    .issues-list li {
      display: flex;
      align-items: flex-start;
      gap: .6rem;
      font-size: .86rem;
      color: var(--text-muted);
      padding: .35rem 0;
      border-bottom: 1px solid rgba(255,255,255,.04);
    }
    .issues-list li:last-child { border-bottom: none; }
    .issue-icon { color: var(--danger); flex-shrink: 0; margin-top: .1rem; }
    .fix-icon   { color: var(--success); flex-shrink: 0; margin-top: .1rem; }

    /* status codes */
    .status-grid {
      display: flex;
      flex-wrap: wrap;
      gap: .5rem;
      margin-top: .8rem;
    }
    .status-chip {
      display: flex;
      align-items: center;
      gap: .4rem;
      padding: .3rem .7rem;
      border-radius: 6px;
      font-size: .78rem;
      font-weight: 600;
    }
    .s-2xx { background: rgba(0,212,170,.12); color: var(--success); border: 1px solid rgba(0,212,170,.25); }
    .s-4xx { background: rgba(255,179,71,.12); color: var(--warning); border: 1px solid rgba(255,179,71,.25); }
    .s-5xx { background: rgba(255,77,109,.12); color: var(--danger);  border: 1px solid rgba(255,77,109,.25); }

    /* sub-heading inside card */
    .sub-heading {
      font-size: .78rem;
      font-weight: 700;
      text-transform: uppercase;
      letter-spacing: .08em;
      color: var(--text-muted);
      margin: 1rem 0 .4rem;
    }

    /* ── Best-practices reference ── */
    .ref-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(280px, 1fr));
      gap: 1rem;
      margin-bottom: 2.5rem;
    }
    .ref-card {
      background: var(--surface);
      border: 1px solid var(--border);
      border-radius: 12px;
      padding: 1.1rem 1.25rem;
    }
    .ref-card h4 {
      font-size: .9rem;
      color: var(--accent2);
      margin-bottom: .6rem;
      display: flex;
      align-items: center;
      gap: .5rem;
    }
    .ref-card ul {
      list-style: none;
      font-size: .82rem;
      color: var(--text-muted);
    }
    .ref-card ul li {
      padding: .22rem 0;
      padding-left: 1.1rem;
      position: relative;
    }
    .ref-card ul li::before {
      content: '▸';
      position: absolute;
      left: 0;
      color: var(--accent);
      font-size: .7rem;
    }

    /* ── Quick-reference table ── */
    .table-wrap { overflow-x: auto; margin-bottom: 2.5rem; }
    table {
      width: 100%;
      border-collapse: collapse;
      font-size: .84rem;
    }
    thead tr { background: var(--surface2); }
    th {
      padding: .75rem 1rem;
      text-align: left;
      font-size: .75rem;
      text-transform: uppercase;
      letter-spacing: .07em;
      color: var(--text-muted);
      border-bottom: 1px solid var(--border);
      white-space: nowrap;
    }
    td {
      padding: .7rem 1rem;
      border-bottom: 1px solid rgba(255,255,255,.04);
      vertical-align: top;
    }
    tr:last-child td { border-bottom: none; }
    tr:hover td { background: rgba(255,255,255,.02); }
    .mono { font-family: 'Cascadia Code','Fira Code',monospace; }

    /* ── Footer ── */
    footer {
      text-align: center;
      padding: 2rem 1rem;
      color: var(--text-muted);
      font-size: .8rem;
      border-top: 1px solid var(--border);
    }
    footer a { color: var(--accent); text-decoration: none; }

    /* ── Animations ── */
    @keyframes fadeIn {
      from { opacity: 0; transform: translateY(12px); }
      to   { opacity: 1; transform: translateY(0); }
    }
    .animate { animation: fadeIn .45s ease both; }
    .delay-1 { animation-delay: .05s; }
    .delay-2 { animation-delay: .1s; }
    .delay-3 { animation-delay: .15s; }
    .delay-4 { animation-delay: .2s; }

    /* ── Expand-all button ── */
    .toolbar {
      display: flex;
      justify-content: flex-end;
      margin-bottom: 1rem;
      gap: .6rem;
    }
    .btn {
      padding: .45rem 1rem;
      border-radius: 8px;
      font-size: .8rem;
      font-weight: 600;
      cursor: pointer;
      border: 1px solid var(--border);
      background: var(--surface);
      color: var(--text);
      transition: background .15s, border-color .15s;
    }
    .btn:hover { background: var(--surface2); border-color: var(--accent); }
    .btn-accent { background: rgba(108,99,255,.15); border-color: rgba(108,99,255,.4); color: var(--accent); }
    .btn-accent:hover { background: rgba(108,99,255,.25); }
  </style>
</head>
