  function toggle(header) {
    const body    = header.nextElementSibling;
    const chevron = header.querySelector('.chevron');
    const isOpen  = body.classList.contains('open');
    body.classList.toggle('open', !isOpen);
    chevron.classList.toggle('open', !isOpen);
  }

  function expandAll() {
    document.querySelectorAll('.card-body').forEach(b => b.classList.add('open'));
    document.querySelectorAll('.chevron').forEach(c => c.classList.add('open'));
  }

  function collapseAll() {
    document.querySelectorAll('.card-body').forEach(b => b.classList.remove('open'));
    document.querySelectorAll('.chevron').forEach(c => c.classList.remove('open'));
  }

  // Open all cards by default so content is immediately visible
  expandAll();
</script>
