    .status-table tr:last-child td { border-bottom: none; }
    .status-table tr:hover td { background: var(--surface2); }
    .status-code {
      font-family: monospace;
      font-weight: 700;
      font-size: .88rem;
      padding: .15rem .45rem;
      border-radius: 4px;
      white-space: nowrap;
    }
    .s2xx { color: var(--success); background: rgba(34,211,165,.12); }
    .s4xx { color: var(--danger);  background: rgba(255,77,109,.12); }
    .s5xx { color: var(--warning); background: rgba(245,158,11,.12); }

    /* ── PRINCIPLES ── */
    .principles-grid {
      display: grid;
      grid-template-columns: repeat(auto-fit, minmax(240px, 1fr));
      gap: 1rem;
      margin-top: 1rem;
    }
    .principle-card {
      background: var(--surface);
      border: 1px solid var(--border);
      border-radius: var(--radius);
      padding: 1.1rem 1rem;
      transition: transform .2s, box-shadow .2s;
    }
    .principle-card:hover { transform: translateY(-2px); box-shadow: var(--shadow); }
    .principle-icon { font-size: 1.5rem; margin-bottom: .5rem; }
    .principle-title { font-weight: 700; font-size: .9rem; margin-bottom: .35rem; color: var(--accent2); }
    .principle-text { font-size: .82rem; color: var(--muted); line-height: 1.55; }

    /* ── QUICK REF ── */
    .quick-ref {
      background: var(--surface);
      border: 1px solid var(--border);
      border-radius: var(--radius);
      overflow: hidden;
      margin-top: 1rem;
    }
    .quick-ref-row {
      display: grid;
      grid-template-columns: 90px 1fr 1fr;
      gap: 0;
      border-bottom: 1px solid var(--border);
    }
    .quick-ref-row:last-child { border-bottom: none; }
    .quick-ref-row.header-row {
      background: var(--surface2);
      font-size: .72rem;
      text-transform: uppercase;
      letter-spacing: .08em;
      color: var(--muted);
    }
