    <div class="quick-ref-row">
      <div class="qr-cell"><span class="method-pill pill-put">PUT</span></div>
      <div class="qr-cell" style="font-family:monospace">/users/{id}</div>
      <div class="qr-cell" style="color:var(--muted)">Full replacement of a user resource</div>
    </div>
    <div class="quick-ref-row">
      <div class="qr-cell"><span class="method-pill pill-patch">PATCH</span></div>
      <div class="qr-cell" style="font-family:monospace">/users/{id}</div>
