    </div>
    <div class="quick-ref-row">
      <div class="qr-cell"><span class="method-pill pill-delete">DELETE</span></div>
      <div class="qr-cell" style="font-family:monospace">/users/{id}</div>
      <div class="qr-cell" style="color:var(--muted)">Delete a user by ID</div>
