<script>
  function toggle(header) {
    const body = header.nextElementSibling;
    const isOpen = body.classList.contains('open');
    body.classList.toggle('open', !isOpen);
    header.classList.toggle('open', !isOpen);
    updateToggleBtn();
  }

  function toggleAll() {
    const headers = document.querySelectorAll('.card-header');
    const bodies  = document.querySelectorAll('.card-body');
    const anyOpen = [...bodies].some(b => b.classList.contains('open'));
    bodies.forEach(b  => b.classList.toggle('open', !anyOpen));
    headers.forEach(h => h.classList.toggle('open', !anyOpen));
    updateToggleBtn();
  }

  function updateToggleBtn() {
    const btn     = document.getElementById('toggleAll');
    const anyOpen = [...document.querySelectorAll('.card-body')].some(b => b.classList.contains('open'));
    btn.textContent = anyOpen ? '▲ Collapse All' : '▼ Expand All';
  }
</script>

</body>
