      padding: 0 1.25rem 1.25rem;
      border-top: 1px solid var(--border);
    }
    .endpoint-doc.open .card-body { display: block; }

    .desc-text {
      color: var(--text-muted);
      font-size: .875rem;
      margin-top: 1rem;
      line-height: 1.7;
    }

    .meta-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(200px, 1fr));
      gap: .75rem;
      margin-top: 1rem;
    }
    .meta-item {
      background: var(--surface2);
      border: 1px solid var(--border);
      border-radius: 8px;
      padding: .75rem 1rem;
    }
    .meta-item .meta-label {
      font-size: .68rem;
      font-weight: 700;
      text-transform: uppercase;
      letter-spacing: .8px;
      color: var(--text-muted);
      margin-bottom: .3rem;
    }
    .meta-item .meta-val {
      font-size: .85rem;
      color: var(--text);
      font-family: 'Cascadia Code', 'Fira Code', monospace;
    }

    .sub-title {
      font-size: .78rem;
      font-weight: 700;
      text-transform: uppercase;
      letter-spacing: .7px;
      color: var(--text-muted);
      margin: 1.25rem 0 .5rem;
    }

    .status-list {
      display: flex;
      flex-wrap: wrap;
      gap: .5rem;
      margin-top: .25rem;
    }
    .status-chip {
      font-size: .78rem;
      padding: .3rem .75rem;
      border-radius: 99px;
      font-family: 'Cascadia Code', 'Fira Code', monospace;
      font-weight: 600;
    }
    .s2xx { background: rgba(72,207,173,.12); color: var(--get);    border: 1px solid rgba(72,207,173,.25); }
    .s4xx { background: rgba(255,179,71,.12);  color: var(--warn);   border: 1px solid rgba(255,179,71,.25); }
    .s5xx { background: rgba(255,92,92,.12);   color: var(--danger); border: 1px solid rgba(255,92,92,.25); }

    pre.code-block {
      background: #0d1020;
      border: 1px solid var(--border);
      border-radius: 8px;
      padding: 1rem 1.25rem;
      overflow-x: auto;
      font-family: 'Cascadia Code', 'Fira Code', monospace;
      font-size: .8rem;
      line-height: 1.7;
      color: #a9b7d0;
      margin-top: .5rem;
    }
    pre.code-block .key   { color: #79b8ff; }
    pre.code-block .str   { color: #9ecbff; }
    pre.code-block .num   { color: var(--accent2); }
    pre.code-block .bool  { color: #ffab70; }
    pre.code-block .punct { color: #6e7f9c; }

    /* ── Principles panel ── */
    .principle-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
      gap: 1rem;
      margin-top: 1rem;
    }
    .principle-card {
      background: var(--surface);
      border: 1px solid var(--border);
      border-radius: var(--radius);
      padding: 1.25rem;
      transition: border-color .2s, transform .2s;
    }
    .principle-card:hover {
      border-color: var(--accent);
      transform: translateY(-2px);
    }
    .principle-icon {
      font-size: 1.75rem;
      margin-bottom: .6rem;
    }
    .principle-card h3 {
      font-size: .95rem;
      font-weight: 600;
      margin-bottom: .4rem;
    }
    .principle-card p {
      font-size: .825rem;
      color: var(--text-muted);
      line-height: 1.6;
    }

    /* ── Comparison table ── */
    .compare-table {
      width: 100%;
      border-collapse: collapse;
      margin-top: 1rem;
      font-size: .85rem;
    }
    .compare-table th {
      background: var(--surface2);
      padding: .75rem 1rem;
      text-align: left;
      font-size: .72rem;
      text-transform: uppercase;
      letter-spacing: .7px;
      color: var(--text-muted);
      border-bottom: 1px solid var(--border);
    }
    .compare-table td {
      padding: .75rem 1rem;
      border-bottom: 1px solid rgba(255,255,255,.04);
      vertical-align: top;
    }
    .compare-table tr:last-child td { border-bottom: none; }
    .compare-table tr:hover td { background: rgba(255,255,255,.02); }
    .compare-table code {
      font-family: 'Cascadia Code', 'Fira Code', monospace;
      font-size: .8rem;
    }
    .old-code { color: var(--danger); }
    .new-code { color: var(--accent2); }

    /* ── Scrollbar ── */
    ::-webkit-scrollbar { width: 6px; height: 6px; }
    ::-webkit-scrollbar-track { background: var(--bg); }
    ::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }

    /* ── Responsive ── */
    @media (max-width: 600px) {
      .meta-grid { grid-template-columns: 1fr 1fr; }
      .compare-table { font-size: .78rem; }
      .compare-table th, .compare-table td { padding: .6rem .75rem; }
    }
  </style>
</head>
<body>

<header>
  <h1>REST API <span>Design Review</span></h1>
  <p>Identifying problems &amp; presenting corrected endpoints following REST best practices</p>
</header>

<!-- ── Tab navigation ── -->
<div class="tabs">
  <button class="tab-btn active" data-tab="problems">⚠️ Problems Found</button>
  <button class="tab-btn" data-tab="corrected">✅ Corrected Endpoints</button>
  <button class="tab-btn" data-tab="comparison">🔄 Before / After</button>
  <button class="tab-btn" data-tab="principles">📐 REST Principles</button>
</div>

<main>

  <!-- ══════════════════════════════════════════
       TAB 1 — Problems Found
  ══════════════════════════════════════════ -->
  <div class="tab-panel active" id="tab-problems">

    <div class="section-title">Original Endpoints — Issues Identified</div>
    <p style="color:var(--text-muted);font-size:.875rem;margin-bottom:1.25rem;">
      Click any endpoint to expand a detailed breakdown of every design violation.
    </p>

    <!-- Problem 1 -->
    <div class="problem-card" id="pc1">
      <div class="card-header" onclick="toggleCard('pc1')">
        <div class="card-header-left">
          <span class="badge-method badge-GET">GET</span>
          <span class="endpoint-path">/getUsers</span>
        </div>
        <span class="chevron">▼</span>
      </div>
      <div class="card-body">
        <ul class="issue-list">
          <li>
            <span class="issue-icon">✖</span>
            <span><strong>Verb in URL path</strong> — REST URLs should identify <em>resources</em> (nouns), not actions.
            The HTTP method (GET) already communicates the intent; adding "get" is redundant and couples
            the URL to a single operation.</span>
          </li>
          <li>
            <span class="issue-icon">✖</span>
            <span><strong>Non-plural resource name</strong> — Collections should use plural nouns
            (<code>/users</code>) to distinguish a collection from a single item (<code>/users/5</code>).</span>
          </li>
          <li>
            <span class="issue-icon">✖</span>
            <span><strong>Inconsistent naming convention</strong> — Mixing camelCase, verbs, and nouns
            across endpoints creates an unpredictable API surface.</span>
          </li>
        </ul>
        <div class="fix-box">
          <span class="fix-label">Fix →</span>
          <code>GET /users</code>
        </div>
      </div>
    </div>

    <!-- Problem 2 -->
    <div class="problem-card" id="pc2">
      <div class="card-header" onclick="toggleCard('pc2')">
        <div class="card-header-left">
          <span class="badge-method badge-POST">POST</span>
          <span class="endpoint-path">/user/delete/5</span>
        </div>
        <span class="chevron">▼</span>
      </div>
      <div class="card-body">
        <ul class="issue-list">
          <li>
            <span class="issue-icon">✖</span>
            <span><strong>Wrong HTTP method for deletion</strong> — <code>POST</code> is for creating resources.
            Deletion must use <code>DELETE</code>, which is also idempotent — calling it multiple times produces
            the same result (resource stays deleted).</span>
          </li>
          <li>
            <span class="issue-icon">✖</span>
            <span><strong>Action verb embedded in path</strong> — <code>/delete</code> is an action, not a resource.
            The HTTP method already expresses deletion; the word is superfluous and pollutes the URL namespace.</span>
          </li>
          <li>
            <span class="issue-icon">✖</span>
            <span><strong>Singular resource name</strong> — Should be <code>/users</code> (plural) for the
            collection, with the ID segment following: <code>/users/5</code>.</span>
          </li>
          <li>
            <span class="issue-icon">✖</span>
            <span><strong>Misleading semantics</strong> — A client or proxy seeing <code>POST /user/delete/5</code>
            may cache or replay the request incorrectly because POST is not safe or idempotent.</span>
          </li>
        </ul>
        <div class="fix-box">
          <span class="fix-label">Fix →</span>
          <code>DELETE /users/5</code>
        </div>
      </div>
    </div>

    <!-- Problem 3 -->
    <div class="problem-card" id="pc3">
      <div class="card-header" onclick="toggleCard('pc3')">
        <div class="card-header-left">
          <span class="badge-method badge-GET">GET</span>
          <span class="endpoint-path">/createUser?name=Jo</span>
        </div>
        <span class="chevron">▼</span>
      </div>
      <div class="card-body">
        <ul class="issue-list">
          <li>
            <span class="issue-icon">✖</span>
            <span><strong>GET used to create a resource</strong> — <code>GET</code> must be <em>safe</em>
            (no side-effects) and <em>idempotent</em>. Creating a resource is a side-effect; the correct
            method is <code>POST</code>. Using GET for mutations also means the request can be cached,
            bookmarked, or accidentally replayed.</span>
          </li>
          <li>
            <span class="issue-icon">✖</span>
            <span><strong>Verb in URL path</strong> — <code>/createUser</code> encodes the action instead
            of the resource. The method <code>POST /users</code> already conveys "create a user".</span>
          </li>
          <li>
            <span class="issue-icon">✖</span>
            <span><strong>Resource data passed as query string</strong> — Creation payload should be sent
            in the request body (JSON), not exposed in the URL. Query strings are logged, cached, and
            visible in browser history, creating security and privacy risks.</span>
          </li>
          <li>
            <span class="issue-icon">✖</span>
            <span><strong>Singular &amp; camelCase resource name</strong> — Should be plural lowercase
            <code>/users</code>.</span>
          </li>
        </ul>
        <div class="fix-box">
          <span class="fix-label">Fix →</span>
          <code>POST /users &nbsp;(body: {"name": "Jo"})</code>
        </div>
      </div>
    </div>

    <!-- Problem 4 -->
    <div class="problem-card" id="pc4">
      <div class="card-header" onclick="toggleCard('pc4')">
        <div class="card-header-left">
          <span class="badge-method badge-PUT">PUT</span>
          <span class="endpoint-path">/updateAllUsers</span>
        </div>
        <span class="chevron">▼</span>
      </div>
      <div class="card-body">
        <ul class="issue-list">
          <li>
            <span class="issue-icon">✖</span>
            <span><strong>Verb in URL path</strong> — <code>/updateAllUsers</code> encodes the action.
            REST URLs should be resource-centric nouns; the HTTP method communicates the action.</span>
          </li>
          <li>
            <span class="issue-icon">✖</span>
            <span><strong>Ambiguous &amp; dangerous bulk operation</strong> — Bulk-updating all users
            via a single endpoint with no scoping is a destructive anti-pattern. If bulk updates are
            truly required, scope them explicitly (e.g., <code>PATCH /users</code> with a filtered body)
            and document them carefully.</span>
          </li>
          <li>
            <span class="issue-icon">✖</span>
            <span><strong>PUT vs PATCH semantics</strong> — <code>PUT</code> replaces an entire resource.
            Partial updates to a collection should use <code>PATCH</code>. If the intent is to fully
            replace every user record, <code>PUT</code> might be technically valid — but the operation
            itself is almost always undesirable.</span>
          </li>
          <li>
            <span class="issue-icon">✖</span>
            <span><strong>camelCase path</strong> — URL paths should be lowercase with hyphens
            (kebab-case) for multi-word segments, e.g., <code>/users</code>.</span>
          </li>
        </ul>
        <div class="fix-box">
          <span class="fix-label">Fix →</span>
          <code>PATCH /users &nbsp;(body: array of partial updates)</code>
        </div>
      </div>
    </div>

  </div><!-- /tab-problems -->


  <!-- ══════════════════════════════════════════
       TAB 2 — Corrected Endpoints
  ══════════════════════════════════════════ -->
  <div class="tab-panel" id="tab-corrected">

    <div class="section-title">Full User Resource — Corrected Endpoints</div>
    <p style="color:var(--text-muted);font-size:.875rem;margin-bottom:1.25rem;">
      Expand each endpoint for description, metadata, expected status codes, and example payloads.
    </p>

    <!-- GET /users -->
    <div class="endpoint-doc" id="ed1">
      <div class="card-header" onclick="toggleCard('ed1')">
        <div class="card-header-left">
          <span class="badge-method badge-GET">GET</span>
          <span class="endpoint-path">/users</span>
        </div>
        <span class="chevron">▼</span>
      </div>
      <div class="card-body">
        <p class="desc-text">
          Returns a paginated list of all users. Supports optional query parameters for filtering,
          sorting, and pagination. This operation is <strong>safe</strong> and <strong>idempotent</strong>.
        </p>
        <div class="meta-grid">
          <div class="meta-item"><div class="meta-label">Method</div><div class="meta-val">GET</div></div>
          <div class="meta-item"><div class="meta-label">Auth Required</div><div class="meta-val">Yes (Bearer)</div></div>
          <div class="meta-item"><div class="meta-label">Idempotent</div><div class="meta-val">✅ Yes</div></div>
          <div class="meta-item"><div class="meta-label">Safe</div><div class="meta-val">✅ Yes</div></div>
        </div>
        <div class="sub-title">Query Parameters</div>
        <pre class="code-block"><span class="key">?page</span>=<span class="num">1</span>&amp;<span class="key">limit</span>=<span class="num">20</span>&amp;<span class="key">sort</span>=<span class="str">name</span>&amp;<span class="key">order</span>=<span class="str">asc</span></pre>
        <div class="sub-title">Response — 200 OK</div>
        <pre class="code-block"><span class="punct">{</span>
  <span class="key">"data"</span><span class="punct">:</span> <span class="punct">[</span>
    <span class="punct">{</span> <span class="key">"id"</span><span class="punct">:</span> <span class="num">1</span><span class="punct">,</span> <span class="key">"name"</span><span class="punct">:</span> <span class="str">"Alice"</span><span class="punct">,</span> <span class="key">"email"</span><span class="punct">:</span> <span class="str">"alice@example.com"</span> <span class="punct">},</span>
    <span class="punct">{</span> <span class="key">"id"</span><span class="punct">:</span> <span class="num">2</span><span class="punct">,</span> <span class="key">"name"</span><span class="punct">:</span> <span class="str">"Bob"</span><span class="punct">,</span>   <span class="key">"email"</span><span class="punct">:</span> <span class="str">"bob@example.com"</span>   <span class="punct">}</span>
  <span class="punct">],</span>
  <span class="key">"meta"</span><span class="punct">:</span> <span class="punct">{</span> <span class="key">"page"</span><span class="punct">:</span> <span class="num">1</span><span class="punct">,</span> <span class="key">"limit"</span><span class="punct">:</span> <span class="num">20</span><span class="punct">,</span> <span class="key">"total"</span><span class="punct">:</span> <span class="num">84</span> <span class="punct">}</span>
<span class="punct">}</span></pre>
        <div class="sub-title">Status Codes</div>
        <div class="status-list">
          <span class="status-chip s2xx">200 OK</span>
          <span class="status-chip s4xx">401 Unauthorized</span>
          <span class="status-chip s4xx">403 Forbidden</span>
          <span class="status-chip s5xx">500 Internal Server Error</span>
        </div>
      </div>
    </div>

    <!-- GET /users/:id -->
    <div class="endpoint-doc" id="ed2">
      <div class="card-header" onclick="toggleCard('ed2')">
        <div class="card-header-left">
          <span class="badge-method badge-GET">GET</span>
          <span class="endpoint-path">/users/:id</span>
        </div>
        <span class="chevron">▼</span>
      </div>
      <div class="card-body">
        <p class="desc-text">
          Retrieves a single user by their unique identifier. Returns <code>404</code> if the user
          does not exist. Safe and idempotent.
        </p>
        <div class="meta-grid">
          <div class="meta-item"><div class="meta-label">Method</div><div class="meta-val">GET</div></div>
          <div class="meta-item"><div class="meta-label">Path Param</div><div class="meta-val">:id (integer)</div></div>
          <div class="meta-item"><div class="meta-label">Idempotent</div><div class="meta-val">✅ Yes</div></div>
          <div class="meta-item"><div class="meta-label">Safe</div><div class="meta-val">✅ Yes</div></div>
        </div>
        <div class="sub-title">Response — 200 OK</div>
        <pre class="code-block"><span class="punct">{</span>
  <span class="key">"id"</span><span class="punct">:</span>    <span class="num">5</span><span class="punct">,</span>
  <span class="key">"name"</span><span class="punct">:</span>  <span class="str">"Jo"</span><span class="punct">,</span>
  <span class="key">"email"</span><span class="punct">:</span> <span class="str">"jo@example.com"</span><span class="punct">,</span>
  <span class="key">"role"</span><span class="punct">:</span>  <span class="str">"editor"</span><span class="punct">,</span>
  <span class="key">"createdAt"</span><span class="punct">:</span> <span class="str">"2024-03-15T10:22:00Z"</span>
<span class="punct">}</span></pre>
        <div class="sub-title">Status Codes</div>
        <div class="status-list">
          <span class="status-chip s2xx">200 OK</span>
          <span class="status-chip s4xx">400 Bad Request</span>
          <span class="status-chip s4xx">401 Unauthorized</span>
          <span class="status-chip s4xx">404 Not Found</span>
          <span class="status-chip s5xx">500 Internal Server Error</span>
        </div>
      </div>
    </div>

    <!-- POST /users -->
    <div class="endpoint-doc" id="ed3">
      <div class="card-header" onclick="toggleCard('ed3')">
        <div class="card-header-left">
          <span class="badge-method badge-POST">POST</span>
          <span class="endpoint-path">/users</span>
        </div>
        <span class="chevron">▼</span>
      </div>
      <div class="card-body">
        <p class="desc-text">
          Creates a new user. The request body must be JSON. On success, returns <code>201 Created</code>
          with the newly created resource and a <code>Location</code> header pointing to the new URL.
          Not idempotent — repeated calls create duplicate resources.
        </p>
        <div class="meta-grid">
          <div class="meta-item"><div class="meta-label">Method</div><div class="meta-val">POST</div></div>
          <div class="meta-item"><div class="meta-label">Content-Type</div><div class="meta-val">application/json</div></div>
          <div class="meta-item"><div class="meta-label">Idempotent</div><div class="meta-val">❌ No</div></div>
          <div class="meta-item"><div class="meta-label">Safe</div><div class="meta-val">❌ No</div></div>
        </div>
        <div class="sub-title">Request Body</div>
        <pre class="code-block"><span class="punct">{</span>
  <span class="key">"name"</span><span class="punct">:</span>     <span class="str">"Jo"</span><span class="punct">,</span>
  <span class="key">"email"</span><span class="punct">:</span>    <span class="str">"jo@example.com"</span><span class="punct">,</span>
  <span class="key">"password"</span><span class="punct">:</span> <span class="str">"••••••••"</span><span class="punct">,</span>
  <span class="key">"role"</span><span class="punct">:</span>     <span class="str">"editor"</span>
<span class="punct">}</span></pre>
        <div class="sub-title">Response — 201 Created</div>
        <pre class="code-block"><span class="punct">{</span>
  <span class="key">"id"</span><span class="punct">:</span>        <span class="num">42</span><span class="punct">,</span>
  <span class="key">"name"</span><span class="punct">:</span>      <span class="str">"Jo"</span><span class="punct">,</span>
  <span class="key">"email"</span><span class="punct">:</span>     <span class="str">"jo@example.com"</span><span class="punct">,</span>
  <span class="key">"createdAt"</span><span class="punct">:</span> <span class="str">"2024-06-01T09:00:00Z"</span>
<span class="punct">}</span>
<span class="key">// Header: Location: /users/42</span></pre>
        <div class="sub-title">Status Codes</div>
        <div class="status-list">
          <span class="status-chip s2xx">201 Created</span>
          <span class="status-chip s4xx">400 Bad Request</span>
          <span class="status-chip s4xx">401 Unauthorized</span>
          <span class="status-chip s4xx">409 Conflict</span>
          <span class="status-chip s4xx">422 Unprocessable Entity</span>
          <span class="status-chip s5xx">500 Internal Server Error</span>
        </div>
      </div>
    </div>

    <!-- PUT /users/:id -->
    <div class="endpoint-doc" id="ed4">
      <div class="card-header" onclick="toggleCard('ed4')">
        <div class="card-header-left">
          <span class="badge-method badge-PUT">PUT</span>
          <span class="endpoint-path">/users/:id</span>
        </div>
        <span class="chevron">▼</span>
      </div>
      <div class="card-body">
        <p class="desc-text">
          Fully replaces an existing user record. All writable fields must be supplied in the body.
          Idempotent — calling it multiple times with the same data produces the same result.
          Use <code>PATCH</code> instead for partial updates.
        </p>
        <div class="meta-grid">
          <div class="meta-item"><div class="meta-label">Method</div><div class="meta-val">PUT</div></div>
          <div class="meta-item"><div class="meta-label">Path Param</div><div class="meta-val">:id (integer)</div></div>
          <div class="meta-item"><div class="meta-label">Idempotent</div><div class="meta-val">✅ Yes</div></div>
          <div class="meta-item"><div class="meta-label">Safe</div><div class="meta-val">❌ No</div></div>
        </div>
        <div class="sub-title">Request Body (full replacement)</div>
        <pre class="code-block"><span class="punct">{</span>
  <span class="key">"name"</span><span class="punct">:</span>  <span class="str">"Jo Updated"</span><span class="punct">,</span>
  <span class="key">"email"</span><span class="punct">:</span> <span class="str">"jo-new@example.com"</span><span class="punct">,</span>
  <span class="key">"role"</span><span class="punct">:</span>  <span class="str">"admin"</span>
<span class="punct">}</span></pre>
        <div class="sub-title">Status Codes</div>
        <div class="status-list">
          <span class="status-chip s2xx">200 OK</span>
          <span class="status-chip s4xx">400 Bad Request</span>
          <span class="status-chip s4xx">401 Unauthorized</span>
          <span class="status-chip s4xx">404 Not Found</span>
          <span class="status-chip s4xx">422 Unprocessable Entity</span>
