    .status-list { display: flex; flex-direction: column; gap: 0.4rem; }

    .status-item {
      display: flex;
      align-items: center;
      gap: 0.6rem;
      font-size: 0.82rem;
    }

    .status-code {
      font-family: 'Courier New', monospace;
      font-size: 0.78rem;
      font-weight: 700;
      padding: 0.1rem 0.45rem;
      border-radius: 5px;
      min-width: 42px;
      text-align: center;
    }

    .s2xx { background: rgba(16,185,129,0.15); color: var(--success); }
    .s4xx { background: rgba(239,68,68,0.15);  color: var(--danger);  }
    .s5xx { background: rgba(107,114,128,0.2); color: #9ca3af; }

    .status-desc { color: var(--muted); }

    /* ── CODE BLOCK ── */
    .code-block {
      background: var(--code-bg);
      border: 1px solid var(--border);
      border-radius: 9px;
      overflow: hidden;
      margin-bottom: 1rem;
    }

    .code-block-header {
      display: flex;
      align-items: center;
      justify-content: space-between;
      padding: 0.5rem 1rem;
      background: var(--surface2);
      border-bottom: 1px solid var(--border);
    }

    .code-lang {
      font-size: 0.7rem;
      text-transform: uppercase;
      letter-spacing: 0.08em;
      color: var(--muted);
    }

    .copy-btn {
      background: none;
      border: 1px solid var(--border);
      color: var(--muted);
      font-size: 0.72rem;
      padding: 0.2rem 0.6rem;
      border-radius: 5px;
      cursor: pointer;
      transition: all 0.2s;
    }

    .copy-btn:hover { border-color: var(--accent); color: var(--accent); }
    .copy-btn.copied { border-color: var(--success); color: var(--success); }

    pre {
      padding: 1rem;
      font-family: 'Courier New', monospace;
      font-size: 0.82rem;
      line-height: 1.7;
      overflow-x: auto;
      color: #abb2bf;
    }

    .kw  { color: #c678dd; }
    .str { color: #98c379; }
    .num { color: #d19a66; }
    .key { color: #e06c75; }
    .cmt { color: #5c6370; font-style: italic; }
    .url { color: #61afef; }

    /* ── COMPARISON TABLE ── */
    .comparison-table {
      width: 100%;
      border-collapse: collapse;
      font-size: 0.83rem;
    }

    .comparison-table th {
      padding: 0.75rem 1rem;
      text-align: left;
      font-size: 0.72rem;
      text-transform: uppercase;
      letter-spacing: 0.08em;
      color: var(--muted);
      background: var(--code-bg);
      border-bottom: 2px solid var(--border);
    }

    .comparison-table td {
      padding: 0.85rem 1rem;
      border-bottom: 1px solid var(--border);
      vertical-align: middle;
    }

    .comparison-table tr:last-child td { border-bottom: none; }
    .comparison-table tr:hover td { background: rgba(255,255,255,0.02); }

    .old-endpoint {
      font-family: 'Courier New', monospace;
      color: var(--danger);
      text-decoration: line-through;
      opacity: 0.8;
    }

    .new-endpoint {
      font-family: 'Courier New', monospace;
      color: var(--success);
    }

    .arrow { color: var(--muted); padding: 0 0.5rem; }

    /* ── STATUS CODES REFERENCE ── */
    .status-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
      gap: 0.75rem;
    }

    .status-ref-item {
      background: var(--surface2);
      border: 1px solid var(--border);
      border-radius: 9px;
      padding: 0.85rem 1rem;
      display: flex;
      gap: 0.75rem;
      align-items: flex-start;
    }

    .status-ref-code {
      font-family: 'Courier New', monospace;
      font-weight: 700;
      font-size: 0.9rem;
      min-width: 42px;
    }

    .status-ref-info h4 { font-size: 0.85rem; font-weight: 600; margin-bottom: 0.2rem; }
    .status-ref-info p  { font-size: 0.78rem; color: var(--muted); }

    /* ── PRINCIPLES ── */
    .principles-grid {
      display: grid;
      grid-template-columns: repeat(auto-fill, minmax(240px, 1fr));
      gap: 0.75rem;
    }

    .principle-card {
      background: var(--surface2);
      border: 1px solid var(--border);
      border-radius: 10px;
      padding: 1rem;
    }

    .principle-card .icon { font-size: 1.4rem; margin-bottom: 0.5rem; }
    .principle-card h4    { font-size: 0.88rem; font-weight: 600; margin-bottom: 0.3rem; }
    .principle-card p     { font-size: 0.78rem; color: var(--muted); line-height: 1.5; }

    /* ── INTRO BANNER ── */
    .intro-banner {
      background: linear-gradient(135deg, rgba(108,99,255,0.15), rgba(167,139,250,0.08));
      border: 1px solid rgba(108,99,255,0.3);
      border-radius: 14px;
      padding: 1.5rem;
      display: flex;
      gap: 1rem;
      align-items: flex-start;
    }

    .intro-banner .icon { font-size: 1.8rem; flex-shrink: 0; }
    .intro-banner h2 { font-size: 1.05rem; font-weight: 700; margin-bottom: 0.4rem; }
    .intro-banner p  { font-size: 0.85rem; color: var(--muted); line-height: 1.6; }

    /* ── TAGS ── */
    .tag {
      display: inline-flex;
      align-items: center;
      gap: 0.3rem;
      font-size: 0.72rem;
      padding: 0.2rem 0.55rem;
      border-radius: 5px;
      font-weight: 600;
    }

    .tag-required { background: rgba(239,68,68,0.15); color: var(--danger); }
    .tag-optional { background: rgba(107,114,128,0.15); color: #9ca3af; }
    .tag-new      { background: rgba(16,185,129,0.15); color: var(--success); }
    .tag-fixed    { background: rgba(108,99,255,0.15); color: var(--accent2); }

    /* ── PARAMS TABLE ── */
    .params-table {
      width: 100%;
      border-collapse: collapse;
      font-size: 0.82rem;
    }

    .params-table th {
      padding: 0.5rem 0.75rem;
      text-align: left;
      font-size: 0.7rem;
      text-transform: uppercase;
      letter-spacing: 0.06em;
      color: var(--muted);
      border-bottom: 1px solid var(--border);
    }

    .params-table td {
      padding: 0.6rem 0.75rem;
      border-bottom: 1px solid rgba(46,50,80,0.5);
      vertical-align: middle;
    }

    .params-table tr:last-child td { border-bottom: none; }

    .param-name {
      font-family: 'Courier New', monospace;
      color: var(--accent2);
    }

    .param-type {
      font-family: 'Courier New', monospace;
      font-size: 0.75rem;
      color: #f472b6;
    }

    /* ── DIVIDER ── */
    .section-divider {
      height: 1px;
      background: linear-gradient(90deg, transparent, var(--border), transparent);
      margin: 0.5rem 0;
    }

    /* ── SCROLLBAR ── */
    ::-webkit-scrollbar { width: 6px; height: 6px; }
    ::-webkit-scrollbar-track { background: var(--bg); }
    ::-webkit-scrollbar-thumb { background: var(--border); border-radius: 3px; }
    ::-webkit-scrollbar-thumb:hover { background: var(--muted); }

    /* ── RESPONSIVE ── */
    @media (max-width: 768px) {
      .container { grid-template-columns: 1fr; }
      .sidebar { position: static; }
      .endpoint-details { grid-template-columns: 1fr; }
      .header-inner { flex-direction: column; align-items: flex-start; }
    }
  </style>
</head>
