                <td><span class="new-endpoint">DELETE /users/5</span></td>
                <td>
                  <span class="tag tag-fixed">Correct method</span>
                  <span class="tag tag-fixed">Verb removed</span>
                  <span class="tag tag-fixed">Plural noun</span>
                </td>
              </tr>
              <tr>
                <td><span class="old-endpoint">GET /createUser?name=Jo</span></td>
                <td><span class="arrow">→</span></td>
                <td><span class="new-endpoint">POST /users</span></td>
                <td>
                  <span class="tag tag-fixed">Correct method</span>
                  <span class="tag tag-fixed">Verb removed</span>
                  <span class="tag tag-fixed">Body payload</span>
                </td>
              </tr>
              <tr>
                <td><span class="old-endpoint">PUT /updateAllUsers</span></td>
                <td><span class="arrow">→</span></td>
                <td><span class="new-endpoint">PATCH /users</span></td>
                <td>
                  <span class="tag tag-fixed">Correct method</span>
