                  <span class="tag tag-new">Bulk PATCH</span>
                </td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>
    </section>

    <!-- ── CORRECTED ENDPOINTS ── -->
    <section id="endpoints">
      <div class="card">
        <div class="card-header" onclick="toggleCard(this)">
          <div class="card-icon" style="background:rgba(16,185,129,0.15)">✅</div>
          <div class="card-title">
            <h2>Corrected API Endpoints</h2>
            <p>Full reference with parameters, request bodies, and response examples</p>
          </div>
          <span class="chevron open">▼</span>
        </div>
        <div class="card-body open">
          <div class="endpoint-list">

            <!-- ── GET /users ── -->
            <div class="endpoint-card">
              <div class="endpoint-header" onclick="toggleEndpoint(this)">
                <span class="method-badge method-get">GET</span>
                <span class="endpoint-path">/users</span>
                <span class="endpoint-summary">List all users (with pagination &amp; filtering)</span>
                <span class="chevron">▼</span>
              </div>
              <div class="endpoint-body">
                <p style="font-size:0.85rem;color:var(--muted);margin-bottom:1rem">
                  Returns a paginated collection of user objects. Supports filtering by status
                  and sorting. This replaces the original broken <code>GET /getUsers</code>.
                </p>

                <div class="endpoint-details">
                  <div class="detail-box">
                    <h4>Query Parameters</h4>
                    <table class="params-table">
                      <thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead>
                      <tbody>
                        <tr>
                          <td class="param-name">page</td>
                          <td class="param-type">integer</td>
                          <td><span class="tag tag-optional">optional</span></td>
                          <td style="color:var(--muted);font-size:0.78rem">Page number (default: 1)</td>
                        </tr>
                        <tr>
                          <td class="param-name">limit</td>
                          <td class="param-type">integer</td>
                          <td><span class="tag tag-optional">optional</span></td>
                          <td style="color:var(--muted);font-size:0.78rem">Items per page (default: 20)</td>
                        </tr>
                        <tr>
                          <td class="param-name">status</td>
                          <td class="param-type">string</td>
                          <td><span class="tag tag-optional">optional</span></td>
                          <td style="color:var(--muted);font-size:0.78rem">Filter: active | inactive</td>
                        </tr>
                      </tbody>
                    </table>
                  </div>
                  <div class="detail-box">
                    <h4>Response Status Codes</h4>
                    <div class="status-list">
                      <div class="status-item">
                        <span class="status-code s2xx">200</span>
                        <span class="status-desc">OK — Returns user array</span>
                      </div>
                      <div class="status-item">
                        <span class="status-code s4xx">400</span>
                        <span class="status-desc">Bad Request — Invalid query params</span>
                      </div>
                      <div class="status-item">
                        <span class="status-code s4xx">401</span>
                        <span class="status-desc">Unauthorized — Missing/invalid token</span>
                      </div>
                      <div class="status-item">
                        <span class="status-code s4xx">403</span>
                        <span class="status-desc">Forbidden — Insufficient permissions</span>
                      </div>
                      <div class="status-item">
                        <span class="status-code s5xx">500</span>
                        <span class="status-desc">Internal Server Error</span>
                      </div>
                    </div>
                  </div>
                </div>

                <div class="code-block">
                  <div class="code-block-header">
                    <span class="code-lang">Example Request</span>
                    <button class="copy-btn" onclick="copyCode(this)">Copy</button>
                  </div>
                  <pre><span class="url">GET /users?page=1&amp;limit=20&amp;status=active</span>
<span class="key">Authorization:</span> <span class="str">Bearer &lt;token&gt;</span>
<span class="key">Accept:</span> <span class="str">application/json</span></pre>
                </div>

                <div class="code-block">
                  <div class="code-block-header">
                    <span class="code-lang">200 OK — Response Body</span>
                    <button class="copy-btn" onclick="copyCode(this)">Copy</button>
                  </div>
                  <pre>{
  <span class="key">"status"</span>: <span class="str">"success"</span>,
  <span class="key">"data"</span>: {
    <span class="key">"users"</span>: [
      {
        <span class="key">"id"</span>: <span class="num">1</span>,
        <span class="key">"name"</span>: <span class="str">"Alice Johnson"</span>,
