  <title>User Management API Reference</title>
  <style>
    :root {
      --bg-primary: #0f1117;
      --bg-secondary: #1a1d2e;
      --bg-card: #1e2235;
      --bg-hover: #252840;
      --accent-blue: #4f8ef7;
      --accent-green: #22c55e;
      --accent-red: #ef4444;
      --accent-yellow: #f59e0b;
      --accent-purple: #a855f7;
      --accent-orange: #f97316;
      --text-primary: #e2e8f0;
      --text-secondary: #94a3b8;
      --text-muted: #64748b;
      --border: #2d3250;
      --border-light: #3d4270;
      --get: #22c55e;
      --post: #4f8ef7;
      --put: #f59e0b;
      --patch: #a855f7;
      --delete: #ef4444;
      --shadow: 0 4px 24px rgba(0,0,0,0.4);
    }

    * { margin: 0; padding: 0; box-sizing: border-box; }

    body {
      font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
      background: var(--bg-primary);
      color: var(--text-primary);
      min-height: 100vh;
      line-height: 1.6;
    }

    /* ── HEADER ── */
    header {
      background: linear-gradient(135deg, #1a1d2e 0%, #0f1117 100%);
      border-bottom: 1px solid var(--border);
      padding: 0 2rem;
      position: sticky;
      top: 0;
      z-index: 100;
      backdrop-filter: blur(12px);
    }

    .header-inner {
      max-width: 1200px;
      margin: 0 auto;
      display: flex;
      align-items: center;
      justify-content: space-between;
      height: 64px;
    }

    .logo {
      display: flex;
      align-items: center;
      gap: 0.75rem;
    }

    .logo-icon {
      width: 36px; height: 36px;
      background: linear-gradient(135deg, var(--accent-blue), var(--accent-purple));
      border-radius: 8px;
      display: flex; align-items: center; justify-content: center;
      font-size: 1.1rem;
    }

    .logo-text { font-size: 1.1rem; font-weight: 700; color: var(--text-primary); }
    .logo-version {
      font-size: 0.7rem; font-weight: 600;
      background: var(--bg-card);
      border: 1px solid var(--border-light);
      color: var(--accent-blue);
      padding: 2px 8px; border-radius: 20px;
    }

    .header-badges { display: flex; gap: 0.5rem; align-items: center; }
    .badge {
      font-size: 0.7rem; font-weight: 600;
      padding: 3px 10px; border-radius: 20px;
    }
    .badge-rest { background: rgba(79,142,247,0.15); color: var(--accent-blue); border: 1px solid rgba(79,142,247,0.3); }
    .badge-stable { background: rgba(34,197,94,0.15); color: var(--accent-green); border: 1px solid rgba(34,197,94,0.3); }

    /* ── LAYOUT ── */
    .container { max-width: 1200px; margin: 0 auto; padding: 2rem; }

    /* ── HERO ── */
    .hero {
      text-align: center;
      padding: 3rem 0 2rem;
    }
    .hero h1 {
      font-size: 2.4rem; font-weight: 800;
      background: linear-gradient(135deg, #e2e8f0, #94a3b8);
      -webkit-background-clip: text; -webkit-text-fill-color: transparent;
      background-clip: text;
      margin-bottom: 0.75rem;
    }
    .hero p { color: var(--text-secondary); font-size: 1.05rem; max-width: 600px; margin: 0 auto 1.5rem; }
    .hero-stats {
      display: flex; justify-content: center; gap: 2rem; flex-wrap: wrap;
    }
    .stat {
      display: flex; flex-direction: column; align-items: center;
      background: var(--bg-card); border: 1px solid var(--border);
      border-radius: 12px; padding: 0.75rem 1.5rem;
    }
    .stat-value { font-size: 1.4rem; font-weight: 700; color: var(--accent-blue); }
    .stat-label { font-size: 0.75rem; color: var(--text-muted); text-transform: uppercase; letter-spacing: 0.05em; }

    /* ── TABS ── */
    .tabs {
      display: flex; gap: 0.25rem;
      background: var(--bg-card);
      border: 1px solid var(--border);
      border-radius: 12px;
      padding: 4px;
      margin: 2rem 0 1.5rem;
      width: fit-content;
    }
    .tab {
      padding: 0.5rem 1.25rem;
      border-radius: 8px;
      border: none;
      background: transparent;
      color: var(--text-muted);
      font-size: 0.875rem; font-weight: 600;
      cursor: pointer;
      transition: all 0.2s;
    }
    .tab.active {
      background: var(--accent-blue);
      color: #fff;
    }
    .tab:hover:not(.active) { background: var(--bg-hover); color: var(--text-primary); }

    .tab-content { display: none; }
    .tab-content.active { display: block; }

    /* ── SECTION CARD ── */
    .section-card {
      background: var(--bg-card);
      border: 1px solid var(--border);
      border-radius: 16px;
      margin-bottom: 1.5rem;
      overflow: hidden;
      box-shadow: var(--shadow);
    }

    .section-header {
      display: flex; align-items: center; justify-content: space-between;
      padding: 1.25rem 1.5rem;
      cursor: pointer;
      transition: background 0.2s;
      user-select: none;
    }
    .section-header:hover { background: var(--bg-hover); }

    .section-title {
      display: flex; align-items: center; gap: 0.75rem;
      font-size: 1rem; font-weight: 700;
    }
    .section-icon {
      width: 32px; height: 32px; border-radius: 8px;
      display: flex; align-items: center; justify-content: center;
      font-size: 1rem;
    }
    .icon-problems { background: rgba(239,68,68,0.15); }
    .icon-corrected { background: rgba(34,197,94,0.15); }
    .icon-codes { background: rgba(79,142,247,0.15); }
    .icon-guide { background: rgba(168,85,247,0.15); }

    .section-meta { display: flex; align-items: center; gap: 0.75rem; }
    .section-count {
      font-size: 0.75rem; font-weight: 600;
      padding: 2px 10px; border-radius: 20px;
      background: var(--bg-primary); border: 1px solid var(--border-light);
      color: var(--text-secondary);
    }
    .chevron {
      color: var(--text-muted); font-size: 0.8rem;
      transition: transform 0.3s;
    }
    .section-card.open .chevron { transform: rotate(180deg); }

    .section-body {
      display: none;
      border-top: 1px solid var(--border);
    }
    .section-card.open .section-body { display: block; }

    /* ── PROBLEMS ── */
    .problems-grid {
      display: grid; grid-template-columns: repeat(auto-fill, minmax(280px, 1fr));
      gap: 1rem; padding: 1.5rem;
    }

    .problem-card {
      background: var(--bg-primary);
      border: 1px solid var(--border);
      border-left: 3px solid var(--accent-red);
      border-radius: 10px;
      padding: 1rem;
      transition: transform 0.2s, box-shadow 0.2s;
    }
    .problem-card:hover { transform: translateY(-2px); box-shadow: 0 8px 24px rgba(0,0,0,0.3); }

    .problem-number {
      display: inline-flex; align-items: center; justify-content: center;
      width: 22px; height: 22px; border-radius: 50%;
      background: rgba(239,68,68,0.2); color: var(--accent-red);
      font-size: 0.7rem; font-weight: 700;
      margin-bottom: 0.5rem;
    }
    .problem-endpoint {
      font-family: 'Courier New', monospace;
      font-size: 0.78rem;
      background: rgba(0,0,0,0.3);
      border: 1px solid var(--border);
      border-radius: 6px;
      padding: 0.4rem 0.6rem;
      margin-bottom: 0.75rem;
      color: var(--accent-red);
      word-break: break-all;
    }
    .problem-title {
      font-size: 0.85rem; font-weight: 700;
      color: var(--text-primary); margin-bottom: 0.35rem;
    }
    .problem-desc { font-size: 0.8rem; color: var(--text-secondary); line-height: 1.5; }
    .problem-rule {
      margin-top: 0.6rem;
      font-size: 0.72rem;
      color: var(--accent-yellow);
      display: flex; align-items: center; gap: 0.3rem;
    }

    /* ── ENDPOINTS ── */
    .endpoints-list { padding: 1.5rem; display: flex; flex-direction: column; gap: 1rem; }

    .endpoint-item {
      background: var(--bg-primary);
      border: 1px solid var(--border);
      border-radius: 12px;
      overflow: hidden;
      transition: box-shadow 0.2s;
    }
    .endpoint-item:hover { box-shadow: 0 4px 20px rgba(0,0,0,0.3); }

    .endpoint-header {
      display: flex; align-items: center; gap: 1rem;
      padding: 1rem 1.25rem;
      cursor: pointer;
    }

    .method-badge {
      font-size: 0.7rem; font-weight: 800;
      padding: 4px 10px; border-radius: 6px;
      min-width: 60px; text-align: center;
      letter-spacing: 0.05em;
    }
    .method-GET    { background: rgba(34,197,94,0.15);  color: var(--get);    border: 1px solid rgba(34,197,94,0.3); }
    .method-POST   { background: rgba(79,142,247,0.15); color: var(--post);   border: 1px solid rgba(79,142,247,0.3); }
    .method-PUT    { background: rgba(245,158,11,0.15); color: var(--put);    border: 1px solid rgba(245,158,11,0.3); }
    .method-PATCH  { background: rgba(168,85,247,0.15); color: var(--patch);  border: 1px solid rgba(168,85,247,0.3); }
    .method-DELETE { background: rgba(239,68,68,0.15);  color: var(--delete); border: 1px solid rgba(239,68,68,0.3); }

    .endpoint-path {
      font-family: 'Courier New', monospace;
      font-size: 0.9rem; font-weight: 600;
      color: var(--text-primary); flex: 1;
    }
    .path-param { color: var(--accent-orange); }

    .endpoint-summary { font-size: 0.8rem; color: var(--text-secondary); }
    .endpoint-tags { display: flex; gap: 0.4rem; flex-wrap: wrap; }
    .endpoint-tag {
      font-size: 0.68rem; padding: 2px 8px; border-radius: 20px;
      background: var(--bg-card); border: 1px solid var(--border-light);
      color: var(--text-muted);
    }

    .endpoint-body {
      display: none;
      border-top: 1px solid var(--border);
      padding: 1.25rem;
    }
    .endpoint-item.open .endpoint-body { display: block; }

    .endpoint-grid { display: grid; grid-template-columns: 1fr 1fr; gap: 1.5rem; }
    @media (max-width: 640px) { .endpoint-grid { grid-template-columns: 1fr; } }

    .detail-section { margin-bottom: 1rem; }
    .detail-label {
      font-size: 0.7rem; font-weight: 700; letter-spacing: 0.08em;
      text-transform: uppercase; color: var(--text-muted);
      margin-bottom: 0.5rem;
    }

    .params-table { width: 100%; border-collapse: collapse; font-size: 0.8rem; }
    .params-table th {
      text-align: left; padding: 0.4rem 0.6rem;
      color: var(--text-muted); font-weight: 600;
      border-bottom: 1px solid var(--border);
    }
    .params-table td { padding: 0.4rem 0.6rem; color: var(--text-secondary); border-bottom: 1px solid rgba(45,50,80,0.5); }
    .param-name { font-family: 'Courier New', monospace; color: var(--accent-blue); }
    .param-type {
      font-size: 0.7rem; padding: 1px 6px; border-radius: 4px;
      background: rgba(79,142,247,0.1); color: var(--accent-blue);
    }
    .param-required {
      font-size: 0.68rem; padding: 1px 6px; border-radius: 4px;
      background: rgba(239,68,68,0.1); color: var(--accent-red);
    }

    .code-block {
      background: rgba(0,0,0,0.4);
      border: 1px solid var(--border);
      border-radius: 8px;
      padding: 0.75rem 1rem;
      font-family: 'Courier New', monospace;
      font-size: 0.78rem;
      color: #a8d8a8;
      overflow-x: auto;
      white-space: pre;
    }

    .responses-list { display: flex; flex-direction: column; gap: 0.4rem; }
    .response-row {
      display: flex; align-items: center; gap: 0.75rem;
      padding: 0.4rem 0.6rem;
      background: rgba(0,0,0,0.2);
      border-radius: 6px;
    }
    .status-code {
      font-family: 'Courier New', monospace;
      font-size: 0.78rem; font-weight: 700;
      min-width: 36px;
    }
    .s2xx { color: var(--get); }
    .s4xx { color: var(--accent-yellow); }
    .s5xx { color: var(--accent-red); }
    .response-desc { font-size: 0.78rem; color: var(--text-secondary); }

    .fix-banner {
      display: flex; align-items: flex-start; gap: 0.75rem;
      background: rgba(34,197,94,0.08);
      border: 1px solid rgba(34,197,94,0.2);
      border-radius: 8px; padding: 0.75rem 1rem;
      margin-bottom: 1rem;
    }
    .fix-icon { font-size: 1rem; margin-top: 1px; }
    .fix-content { font-size: 0.8rem; color: var(--text-secondary); line-height: 1.5; }
    .fix-content strong { color: var(--accent-green); }

    /* ── STATUS CODES TABLE ── */
    .codes-table-wrap { padding: 1.5rem; }
    .codes-table { width: 100%; border-collapse: collapse; font-size: 0.85rem; }
    .codes-table thead tr { border-bottom: 2px solid var(--border); }
    .codes-table th {
      text-align: left; padding: 0.6rem 1rem;
      color: var(--text-muted); font-weight: 700;
      font-size: 0.75rem; text-transform: uppercase; letter-spacing: 0.06em;
    }
    .codes-table tbody tr {
      border-bottom: 1px solid rgba(45,50,80,0.5);
      transition: background 0.15s;
    }
    .codes-table tbody tr:hover { background: var(--bg-hover); }
    .codes-table td { padding: 0.65rem 1rem; }
    .code-pill {
      font-family: 'Courier New', monospace;
      font-size: 0.8rem; font-weight: 700;
      padding: 3px 10px; border-radius: 6px;
      display: inline-block;
    }
    .pill-2xx { background: rgba(34,197,94,0.15); color: var(--get); }
    .pill-4xx { background: rgba(245,158,11,0.15); color: var(--put); }
    .pill-5xx { background: rgba(239,68,68,0.15); color: var(--delete); }
    .code-name { font-weight: 600; color: var(--text-primary); }
    .code-use { color: var(--text-secondary); font-size: 0.8rem; }
    .code-ops { display: flex; gap: 0.3rem; flex-wrap: wrap; }
    .code-op {
      font-size: 0.68rem; padding: 1px 7px; border-radius: 4px;
      background: var(--bg-primary); border: 1px solid var(--border);
      color: var(--text-muted);
    }

    /* ── BEST PRACTICES ── */
    .practices-grid {
      display: grid; grid-template-columns: repeat(auto-fill, minmax(260px, 1fr));
      gap: 1rem; padding: 1.5rem;
    }
    .practice-card {
      background: var(--bg-primary);
      border: 1px solid var(--border);
      border-radius: 10px;
      padding: 1.1rem;
    }
    .practice-icon { font-size: 1.4rem; margin-bottom: 0.5rem; }
    .practice-title { font-size: 0.9rem; font-weight: 700; margin-bottom: 0.35rem; color: var(--text-primary); }
    .practice-desc { font-size: 0.8rem; color: var(--text-secondary); line-height: 1.5; }
    .practice-example {
      margin-top: 0.6rem;
      font-family: 'Courier New', monospace;
      font-size: 0.73rem;
      background: rgba(0,0,0,0.3);
      border-radius: 6px; padding: 0.4rem 0.6rem;
      color: var(--accent-green);
    }

    /* ── COMPARISON TABLE ── */
    .compare-wrap { padding: 1.5rem; }
    .compare-table { width: 100%; border-collapse: collapse; font-size: 0.82rem; }
    .compare-table thead tr { border-bottom: 2px solid var(--border); }
    .compare-table th {
      padding: 0.6rem 1rem; text-align: left;
      font-size: 0.75rem; font-weight: 700;
      text-transform: uppercase; letter-spacing: 0.06em;
      color: var(--text-muted);
    }
    .compare-table tbody tr { border-bottom: 1px solid rgba(45,50,80,0.5); }
    .compare-table tbody tr:hover { background: var(--bg-hover); }
    .compare-table td { padding: 0.7rem 1rem; vertical-align: top; }
    .bad-code {
      font-family: 'Courier New', monospace; font-size: 0.78rem;
      color: var(--accent-red); background: rgba(239,68,68,0.08);
      padding: 2px 6px; border-radius: 4px; text-decoration: line-through;
    }
    .good-code {
      font-family: 'Courier New', monospace; font-size: 0.78rem;
      color: var(--accent-green); background: rgba(34,197,94,0.08);
      padding: 2px 6px; border-radius: 4px;
    }
    .issue-text { color: var(--text-secondary); font-size: 0.78rem; }

    /* ── FOOTER ── */
    footer {
      border-top: 1px solid var(--border);
      margin-top: 3rem; padding: 1.5rem 2rem;
      text-align: center; color: var(--text-muted); font-size: 0.8rem;
    }

    /* ── SCROLLBAR ── */
    ::-webkit-scrollbar { width: 6px; height: 6px; }
    ::-webkit-scrollbar-track { background: var(--bg-primary); }
    ::-webkit-scrollbar-thumb { background: var(--border-light); border-radius: 3px; }

    /* ── RESPONSIVE ── */
    @media (max-width: 768px) {
      .hero h1 { font-size: 1.7rem; }
      .problems-grid { grid-template-columns: 1fr; }
      .tabs { flex-wrap: wrap; width: 100%; }
    }
  </style>
</head>
<body>

<!-- ═══════════════════════════ HEADER ═══════════════════════════ -->
<header>
  <div class="header-inner">
    <div class="logo">
      <div class="logo-icon">👤</div>
      <span class="logo-text">UserMgmt API</span>
      <span class="logo-version">v2.0</span>
    </div>
    <div class="header-badges">
      <span class="badge badge-rest">RESTful</span>
      <span class="badge badge-stable">Stable</span>
    </div>
  </div>
</header>

<!-- ═══════════════════════════ MAIN ═══════════════════════════ -->
<main class="container">

  <!-- Hero -->
  <div class="hero">
    <h1>User Management API Reference</h1>
    <p>A complete audit and redesign of a poorly structured REST API — with identified problems, corrected endpoints, and industry best practices.</p>
    <div class="hero-stats">
      <div class="stat"><span class="stat-value">4</span><span class="stat-label">Endpoints Audited</span></div>
      <div class="stat"><span class="stat-value">12</span><span class="stat-label">Issues Found</span></div>
      <div class="stat"><span class="stat-value">5</span><span class="stat-label">Corrected Endpoints</span></div>
      <div class="stat"><span class="stat-value">8</span><span class="stat-label">Status Codes</span></div>
    </div>
  </div>

  <!-- Tabs -->
  <div class="tabs">
    <button class="tab active" onclick="switchTab('audit')">🔍 Audit Report</button>
    <button class="tab" onclick="switchTab('endpoints')">✅ Corrected API</button>
    <button class="tab" onclick="switchTab('codes')">📋 Status Codes</button>
    <button class="tab" onclick="switchTab('guide')">📖 Best Practices</button>
  </div>

  <!-- ═══════════ TAB: AUDIT ═══════════ -->
  <div id="tab-audit" class="tab-content active">

    <!-- Problems Found -->
    <div class="section-card open" id="card-problems">
      <div class="section-header" onclick="toggleCard('card-problems')">
        <div class="section-title">
          <div class="section-icon icon-problems">🚨</div>
          Design Problems in Original Endpoints
        </div>
        <div class="section-meta">
          <span class="section-count">12 issues</span>
          <span class="chevron">▼</span>
        </div>
      </div>
      <div class="section-body">
        <div class="problems-grid">

          <!-- Problem 1 -->
          <div class="problem-card">
            <div class="problem-number">1</div>
            <div class="problem-endpoint">GET /getUsers</div>
            <div class="problem-title">Verb in URL path</div>
            <div class="problem-desc">REST URLs should identify <em>resources</em>, not <em>actions</em>. The HTTP method (GET) already communicates the action — adding "get" is redundant.</div>
            <div class="problem-rule">⚠️ Rule: Nouns, not verbs in URIs</div>
          </div>

          <!-- Problem 2 -->
          <div class="problem-card">
            <div class="problem-number">2</div>
            <div class="problem-endpoint">GET /getUsers</div>
            <div class="problem-title">Inconsistent naming convention</div>
            <div class="problem-desc">Uses camelCase ("getUsers"). REST APIs should use lowercase, hyphen-separated words (kebab-case) for multi-word resource names.</div>
            <div class="problem-rule">⚠️ Rule: Consistent lowercase naming</div>
          </div>

          <!-- Problem 3 -->
          <div class="problem-card">
            <div class="problem-number">3</div>
            <div class="problem-endpoint">POST /user/delete/5</div>
            <div class="problem-title">Wrong HTTP method for deletion</div>
            <div class="problem-desc">Using POST to delete a resource violates HTTP semantics. DELETE is the correct method — it is idempotent and semantically accurate.</div>
            <div class="problem-rule">⚠️ Rule: Use DELETE for deletions</div>
          </div>

          <!-- Problem 4 -->
          <div class="problem-card">
            <div class="problem-number">4</div>
            <div class="problem-endpoint">POST /user/delete/5</div>
            <div class="problem-title">Action verb embedded in URL</div>
            <div class="problem-desc">"delete" is an action, not a resource. The URL already has the resource (/user/5) and the HTTP method should convey the action.</div>
            <div class="problem-rule">⚠️ Rule: HTTP method = action</div>
          </div>

          <!-- Problem 5 -->
          <div class="problem-card">
            <div class="problem-number">5</div>
            <div class="problem-endpoint">POST /user/delete/5</div>
            <div class="problem-title">Singular resource name</div>
            <div class="problem-desc">Collections should use plural nouns (/users, not /user). This makes it clear you're working with a collection and a specific member of it.</div>
            <div class="problem-rule">⚠️ Rule: Plural resource names</div>
          </div>

          <!-- Problem 6 -->
          <div class="problem-card">
            <div class="problem-number">6</div>
            <div class="problem-endpoint">GET /createUser?name=Jo</div>
            <div class="problem-title">GET used for resource creation</div>
            <div class="problem-desc">GET requests must be safe (no side effects). Creating a resource is a side effect — POST must be used. GET requests can be cached and bookmarked.</div>
            <div class="problem-rule">⚠️ Rule: GET must be safe &amp; idempotent</div>
          </div>

          <!-- Problem 7 -->
          <div class="problem-card">
            <div class="problem-number">7</div>
            <div class="problem-endpoint">GET /createUser?name=Jo</div>
            <div class="problem-title">Sensitive data in query string</div>
            <div class="problem-desc">Passing user data as query parameters exposes it in server logs, browser history, and referrer headers. Request body should be used instead.</div>
            <div class="problem-rule">⚠️ Rule: Body for sensitive/complex data</div>
          </div>

          <!-- Problem 8 -->
          <div class="problem-card">
            <div class="problem-number">8</div>
            <div class="problem-endpoint">GET /createUser?name=Jo</div>
            <div class="problem-title">Verb in URL path (again)</div>
            <div class="problem-desc">"createUser" combines a verb and a noun. The endpoint should be /users (the collection) and POST implies creation.</div>
            <div class="problem-rule">⚠️ Rule: Nouns only in URIs</div>
          </div>

          <!-- Problem 9 -->
          <div class="problem-card">
            <div class="problem-number">9</div>
            <div class="problem-endpoint">PUT /updateAllUsers</div>
            <div class="problem-title">Dangerous bulk operation without safeguard</div>
            <div class="problem-desc">Updating ALL users in one call with no filtering or confirmation is extremely risky. Bulk operations need careful design with explicit scope.</div>
            <div class="problem-rule">⚠️ Rule: Explicit scope for bulk ops</div>
          </div>

          <!-- Problem 10 -->
          <div class="problem-card">
            <div class="problem-number">10</div>
            <div class="problem-endpoint">PUT /updateAllUsers</div>
            <div class="problem-title">Verb in URL path (again)</div>
            <div class="problem-desc">"update" is an action verb. The URL should be /users (the collection resource) and PUT/PATCH communicates the update intent.</div>
            <div class="problem-rule">⚠️ Rule: Nouns, not verbs</div>
          </div>

          <!-- Problem 11 -->
          <div class="problem-card">
            <div class="problem-number">11</div>
            <div class="problem-endpoint">PUT /updateAllUsers</div>
            <div class="problem-title">PUT vs PATCH misuse</div>
            <div class="problem-desc">PUT replaces an entire resource (full update). For partial updates — which "updateAll" implies — PATCH is the correct and semantically precise method.</div>
            <div class="problem-rule">⚠️ Rule: PATCH for partial updates</div>
          </div>

          <!-- Problem 12 -->
          <div class="problem-card">
            <div class="problem-number">12</div>
            <div class="problem-endpoint">All endpoints</div>
            <div class="problem-title">No API versioning</div>
            <div class="problem-desc">None of the endpoints include version information (/v1/). Without versioning, any breaking change will break all existing clients immediately.</div>
            <div class="problem-rule">⚠️ Rule: Version your API from day one</div>
          </div>

        </div>
      </div>
    </div>

    <!-- Side-by-side comparison -->
    <div class="section-card open" id="card-compare">
      <div class="section-header" onclick="toggleCard('card-compare')">
        <div class="section-title">
          <div class="section-icon icon-problems">⚖️</div>
          Before vs. After Comparison
        </div>
        <div class="section-meta">
          <span class="section-count">4 endpoints</span>
          <span class="chevron">▼</span>
        </div>
      </div>
      <div class="section-body">
        <div class="compare-wrap">
          <table class="compare-table">
            <thead>
              <tr>
                <th>Original (Broken)</th>
                <th>Corrected</th>
                <th>Key Issues Fixed</th>
              </tr>
            </thead>
            <tbody>
              <tr>
                <td><span class="bad-code">GET /getUsers</span></td>
                <td><span class="good-code">GET /v1/users</span></td>
                <td class="issue-text">Removed verb, added versioning, plural noun</td>
              </tr>
              <tr>
                <td><span class="bad-code">POST /user/delete/5</span></td>
                <td><span class="good-code">DELETE /v1/users/{id}</span></td>
                <td class="issue-text">Correct method, removed verb, plural noun, path param</td>
              </tr>
              <tr>
                <td><span class="bad-code">GET /createUser?name=Jo</span></td>
                <td><span class="good-code">POST /v1/users</span></td>
                <td class="issue-text">Correct method, data in body, removed verb, versioned</td>
              </tr>
              <tr>
                <td><span class="bad-code">PUT /updateAllUsers</span></td>
                <td><span class="good-code">PATCH /v1/users</span></td>
                <td class="issue-text">PATCH for partial update, removed verb, versioned</td>
              </tr>
              <tr>
                <td colspan="3" style="padding: 0.5rem 1rem; color: var(--text-muted); font-size:0.78rem; font-style:italic;">
                  ✨ Bonus endpoint added: GET /v1/users/{id} — retrieving a single user is a fundamental operation that was missing entirely.
                </td>
              </tr>
            </tbody>
          </table>
        </div>
      </div>
    </div>

  </div><!-- /tab-audit -->

  <!-- ═══════════ TAB: ENDPOINTS ═══════════ -->
  <div id="tab-endpoints" class="tab-content">

    <div class="section-card open" id="card-endpoints">
      <div class="section-header" onclick="toggleCard('card-endpoints')">
        <div class="section-title">
          <div class="section-icon icon-corrected">✅</div>
          Corrected REST Endpoints
        </div>
        <div class="section-meta">
          <span class="section-count">5 endpoints</span>
          <span class="chevron">▼</span>
        </div>
      </div>
      <div class="section-body">
        <div class="endpoints-list">

          <!-- GET /v1/users -->
          <div class="endpoint-item" id="ep-1">
            <div class="endpoint-header" onclick="toggleEndpoint('ep-1')">
              <span class="method-badge method-GET">GET</span>
              <span class="endpoint-path">/v1/users</span>
              <span class="endpoint-summary">List all users</span>
              <div class="endpoint-tags">
                <span class="endpoint-tag">Users</span>
                <span class="endpoint-tag">Collection</span>
              </div>
            </div>
            <div class="endpoint-body">
              <div class="fix-banner">
                <span class="fix-icon">🔧</span>
                <div class="fix-content">
                  <strong>Fixed from:</strong> <code>GET /getUsers</code> — Removed the verb "get" from the URL (the HTTP method already communicates the action), added API versioning (/v1/), and ensured the resource name is a plural noun.
                </div>
              </div>
              <div class="endpoint-grid">
                <div>
                  <div class="detail-section">
                    <div class="detail-label">Query Parameters</div>
                    <table class="params-table">
                      <thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead>
                      <tbody>
                        <tr><td class="param-name">page</td><td><span class="param-type">integer</span></td><td>—</td><td>Page number (default: 1)</td></tr>
                        <tr><td class="param-name">limit</td><td><span class="param-type">integer</span></td><td>—</td><td>Results per page (default: 20)</td></tr>
                        <tr><td class="param-name">sort</td><td><span class="param-type">string</span></td><td>—</td><td>Sort field (e.g. name, created_at)</td></tr>
                        <tr><td class="param-name">order</td><td><span class="param-type">string</span></td><td>—</td><td>asc or desc</td></tr>
                      </tbody>
                    </table>
                  </div>
                  <div class="detail-section">
                    <div class="detail-label">Responses</div>
                    <div class="responses-list">
                      <div class="response-row"><span class="status-code s2xx">200</span><span class="response-desc">OK — Returns paginated list of users</span></div>
                      <div class="response-row"><span class="status-code s4xx">401</span><span class="response-desc">Unauthorized — Missing or invalid token</span></div>
                      <div class="response-row"><span class="status-code s4xx">403</span><span class="response-desc">Forbidden — Insufficient permissions</span></div>
                      <div class="response-row"><span class="status-code s5xx">500</span><span class="response-desc">Internal Server Error</span></div>
                    </div>
                  </div>
                </div>
                <div>
                  <div class="detail-section">
                    <div class="detail-label">Example Response (200)</div>
                    <div class="code-block">{
  "data": [
    {
      "id": 1,
      "name": "Alice Johnson",
      "email": "alice@example.com",
      "created_at": "2024-01-15T10:30:00Z"
    }
  ],
  "pagination": {
    "page": 1,
    "limit": 20,
    "total": 142,
    "pages": 8
  }
}</div>
                  </div>
                </div>
              </div>
            </div>
          </div>

          <!-- GET /v1/users/{id} -->
          <div class="endpoint-item" id="ep-2">
            <div class="endpoint-header" onclick="toggleEndpoint('ep-2')">
              <span class="method-badge method-GET">GET</span>
              <span class="endpoint-path">/v1/users/<span class="path-param">{id}</span></span>
              <span class="endpoint-summary">Get a single user</span>
              <div class="endpoint-tags">
                <span class="endpoint-tag">Users</span>
                <span class="endpoint-tag">Resource</span>
                <span class="endpoint-tag">New</span>
              </div>
            </div>
            <div class="endpoint-body">
              <div class="fix-banner">
                <span class="fix-icon">✨</span>
                <div class="fix-content">
                  <strong>New endpoint added:</strong> The original API had no way to fetch a single user. This is a fundamental REST operation and follows the standard <code>/collection/{id}</code> pattern.
                </div>
              </div>
              <div class="endpoint-grid">
                <div>
                  <div class="detail-section">
                    <div class="detail-label">Path Parameters</div>
                    <table class="params-table">
