          <!-- POST /v1/users -->
          <div class="endpoint-item" id="ep-3">
            <div class="endpoint-header" onclick="toggleEndpoint('ep-3')">
              <span class="method-badge method-POST">POST</span>
              <span class="endpoint-path">/v1/users</span>
              <span class="endpoint-summary">Create a new user</span>
              <div class="endpoint-tags">
                <span class="endpoint-tag">Users</span>
                <span class="endpoint-tag">Mutation</span>
