                        <tr><td class="param-name">email</td><td><span class="param-type">string</span></td><td><span class="param-required">required</span></td><td>Valid email address</td></tr>
                        <tr><td class="param-name">password</td><td><span class="param-type">string</span></td><td><span class="param-required">required</span></td><td>Min 8 chars</td></tr>
