                    </div>
                  </div>
                </div>
                <div>
                  <div class="detail-section">
                    <div class="detail-label">Example Request Body</div>
                    <div class="code-block">{
  "name": "Jo Smith",
  "email": "jo@example.com",
  "password": "Secur3Pass!",
  "role": "user"
}</div>
                  </div>
                  <div class="detail-section">
                    <div class="detail-label">Example Response (201)</div>
                    <div class="code-block">{
  "id": 143,
  "name": "Jo Smith",
  "email": "jo@example.com",
  "role": "user",
  "created_at": "2024-07-01T12:00:00Z"
}</div>
                  </div>
                </div>
              </div>
            </div>
          </div>

          <!-- PATCH /v1/users -->
          <div class="endpoint-item" id="ep-4">
            <div class="endpoint-header" onclick="toggleEndpoint('ep-4')">
              <span class="method-badge method-PATCH">PATCH</span>
              <span class="endpoint-path">/v1/users</span>
              <span class="endpoint-summary">Bulk partial update of users</span>
              <div class="endpoint-tags">
                <span class="endpoint-tag">Users</span>
                <span class="endpoint-tag">Bulk</span>
                <span class="endpoint-tag">Dangerous</span>
              </div>
            </div>
            <div class="endpoint-body">
              <div class="fix-banner">
                <span class="fix-icon">🔧</span>
                <div class="fix-content">
                  <strong>Fixed from:</strong> <code>PUT /updateAllUsers</code> — Changed to PATCH (partial update, not full replacement), removed verb from URL, added versioning. Also added a required <code>filter</code> field in the body to prevent accidental mass updates.
                </div>
              </div>
              <div class="endpoint-grid">
                <div>
                  <div class="detail-section">
                    <div class="detail-label">Request Body (application/json)</div>
                    <table class="params-table">
                      <thead><tr><th>Field</th><th>Type</th><th>Required</th><th>Description</th></tr></thead>
                      <tbody>
                        <tr><td class="param-name">filter</td><td><span class="param-type">object</span></td><td><span class="param-required">required</span></td><td>Criteria to select users</td></tr>
                        <tr><td class="param-name">update</td><td><span class="param-type">object</span></td><td><span class="param-required">required</span></td><td>Fields to update</td></tr>
                      </tbody>
                    </table>
                  </div>
                  <div class="detail-section">
                    <div class="detail-label">Responses</div>
                    <div class="responses-list">
                      <div class="response-row"><span class="status-code s2xx">200</span><span class="response-desc">OK — Returns count of updated users</span></div>
                      <div class="response-row"><span class="status-code s4xx">400</span><span class="response-desc">Bad Request — Missing filter or update</span></div>
                      <div class="response-row"><span class="status-code s4xx">403</span><span class="response-desc">Forbidden — Admin only</span></div>
                    </div>
                  </div>
                </div>
                <div>
                  <div class="detail-section">
                    <div class="detail-label">Example Request Body</div>
                    <div class="code-block">{
  "filter": { "role": "user" },
  "update": { "status": "active" }
}</div>
                  </div>
                  <div class="detail-section">
                    <div class="detail-label">Example Response (200)</div>
                    <div class="code-block">{
  "updated": 87,
  "message": "87 users updated successfully."
}</div>
                  </div>
                </div>
              </div>
            </div>
          </div>

          <!-- DELETE /v1/users/{id} -->
          <div class="endpoint-item" id="ep-5">
            <div class="endpoint-header" onclick="toggleEndpoint('ep-5')">
              <span class="method-badge method-DELETE">DELETE</span>
              <span class="endpoint-path">/v1/users/<span class="path-param">{id}</span></span>
              <span class="endpoint-summary">Delete a user</span>
              <div class="endpoint-tags">
                <span class="endpoint-tag">Users</span>
                <span class="endpoint-tag">Mutation</span>
              </div>
            </div>
            <div class="endpoint-body">
              <div class="fix-banner">
                <span class="fix-icon">🔧</span>
                <div class="fix-content">
                  <strong>Fixed from:</strong> <code>POST /user/delete/5</code> — Changed to DELETE method (semantically correct, idempotent), removed the "delete" verb from the URL, changed singular "user" to plural "users", added versioning. The ID is a path parameter.
                </div>
              </div>
              <div class="endpoint-grid">
                <div>
                  <div class="detail-section">
                    <div class="detail-label">Path Parameters</div>
                    <table class="params-table">
                      <thead><tr><th>Name</th><th>Type</th><th>Required</th><th>Description</th></tr></thead>
                      <tbody>
                        <tr><td class="param-name">id</td><td><span class="param-type">integer</span></td><td><span class="param-required">required</span></td><td>ID of user to delete</td></tr>
                      </tbody>
                    </table>
                  </div>
                  <div class="detail-section">
                    <div class="detail-label">Responses</div>
                    <div class="responses-list">
                      <div class="response-row"><span class="status-code s2xx">204</span><span class="response-desc">No Content — User deleted successfully</span></div>
                      <div class="response-row"><span class="status-code s4xx">404</span><span class="response-desc">Not Found — User does not exist</span></div>
                      <div class="response-row"><span class="status-code s4xx">401</span><span class="response-desc">Unauthorized</span></div>
                      <div class="response-row"><span class="status-code s4xx">403</span><span class="response-desc">Forbidden — Cannot delete this user</span></div>
                    </div>
                  </div>
                </div>
                <div>
                  <div class="detail-section">
                    <div class="detail-label">Notes</div>
                    <div class="code-block">// 204 No Content returns no body.
// The operation is idempotent:
// DELETE /v1/users/5 called twice
// returns 204 first time,
// 404 second time — both are valid.</div>
                  </div>
                </div>
              </div>
            </div>
          </div>

        </div>
      </div>
    </div>

  </div><!-- /tab-endpoints -->

