                <td><div class="code-ops"><span class="code-op">POST</span></div></td>
              </tr>
              <tr>
                <td><span class="code-pill pill-2xx">204</span></td>
                <td class="code-name">No Content</td>
                <td class="code-use">Request succeeded but there is no body to return. Used for deletions.</td>
                <td><div class="code-ops"><span class="code-op">DELETE</span><span class="code-op">PUT</span></div></td>
              </tr>
              <tr>
                <td><span class="code-pill pill-4xx">400</span></td>
                <td class="code-name">Bad Request</td>
                <td class="code-use">The request is malformed, missing required fields, or fails validation. Include error details in the body.</td>
                <td><div class="code-ops"><span class="code-op">POST</span><span class="code-op">PUT</span><span class="code-op">PATCH</span></div></td>
              </tr>
              <tr>
                <td><span class="code-pill pill-4xx">401</span></td>
                <td class="code-name">Unauthorized</td>
                <td class="code-use">Authentication is required and has failed or not been provided. The client must authenticate.</td>
                <td><div class="code-ops"><span class="code-op">ALL</span></div></td>
              </tr>
              <tr>
                <td><span class="code-pill pill-4xx">403</span></td>
                <td class="code-name">Forbidden</td>
                <td class="code-use">Authenticated but not authorized. The server understood the request but refuses to fulfill it.</td>
                <td><div class="code-ops"><span class="code-op">ALL</span></div></td>
              </tr>
              <tr>
                <td><span class="code-pill pill-4xx">404</span></td>
                <td class="code-name">Not Found</td>
                <td class="code-use">The requested resource does not exist. Also used to hide existence of forbidden resources.</td>
                <td><div class="code-ops"><span class="code-op">GET</span><span class="code-op">DELETE</span><span class="code-op">PATCH</span></div></td>
              </tr>
              <tr>
                <td><span class="code-pill pill-4xx">409</span></td>
                <td class="code-name">Conflict</td>
                <td class="code-use">The request conflicts with current server state. E.g., duplicate email on registration.</td>
                <td><div class="code-ops"><span class="code-op">POST</span><span class="code-op">PUT</span></div></td>
              </tr>
            </tbody>
          </table>
        </div>
