  <div class="endpoint-card" id="card4">
    <div class="card-header" onclick="toggleCard('card4')">
      <span class="method-badge m-put">PUT</span>
      <span class="endpoint-path">/updateAllUsers</span>
      <span class="endpoint-summary">Update all users (bulk)</span>
      <span class="chevron">▼</span>
    </div>
    <div class="card-body">
      <div class="tabs">
