          <pre><span class="http-method">PUT</span> <span class="http-path">/v1/users/5</span> HTTP/1.1
<span class="http-header">Content-Type:</span> <span class="http-value">application/json</span>

{
  <span class="json-key">"name"</span>:  <span class="json-str">"Jo Updated Smith"</span>,
  <span class="json-key">"email"</span>: <span class="json-str">"jo.new@example.com"</span>,
  <span class="json-key">"role"</span>:  <span class="json-str">"admin"</span>
}</pre>
