<!-- ENDPOINT 1: GET /getUsers               -->
<!-- ======================================== -->
<div class="endpoint-card">
    <div class="endpoint-header" onclick="toggle('ep1')">
        <span class="method-badge method-get">GET</span>
        <span class="endpoint-url bad">/getUsers</span>
        <span class="endpoint-desc">Retrieve all users</span>
        <span class="tag tag-severity-med">3 Issues</span>
        <span class="chevron" id="chevron-ep1">▼</span>
    </div>

    <div class="arrow-row">
        <span class="old-endpoint">GET /getUsers</span>
        <span class="arrow">→</span>
        <span class="new-endpoint">GET /users</span>
    </div>

    <div class="endpoint-body" id="ep1">
        <div class="body-inner">
            <div class="two-col">
                <div class="problem-box">
                    <div class="box-title red">⚠ Problems Identified</div>
                    <ul class="problem-list">
                        <li>
                            <span class="icon">🔴</span>
                            <span><strong>Verb in URL:</strong> <code style="color:#f87171">getUsers</code> uses an action verb. REST URLs must represent resources (nouns), not operations. The HTTP method already expresses the action.</span>
                        </li>
                        <li>
                            <span class="icon">🟡</span>
                            <span><strong>Redundant naming:</strong> Prefixing with "get" is redundant because a GET request already implies retrieval. It creates noise without adding meaning.</span>
                        </li>
                        <li>
                            <span class="icon">🟡</span>
                            <span><strong>Inconsistency risk:</strong> This pattern leads to chaos — you'd end up with <code style="color:#f87171">/getUsers</code>, <code style="color:#f87171">/deleteUser</code>, <code style="color:#f87171">/createUser</code> instead of a uniform resource-based structure.</span>
                        </li>
                    </ul>
                </div>
                <div class="fix-box">
                    <div class="box-title green">✅ Fixes Applied</div>
                    <ul class="problem-list">
                        <li>
                            <span class="icon">✓</span>
                            <span>Renamed to <code style="color:#4ade80">/users</code> — a clean, plural noun representing the resource collection.</span>
                        </li>
                        <li>
                            <span class="icon">✓</span>
                            <span>HTTP method <strong>GET</strong> is retained and correct — it's safe (no side effects) and idempotent (same result every call).</span>
                        </li>
                        <li>
                            <span class="icon">✓</span>
                            <span>Added support for query parameters for filtering, pagination, and sorting: <code style="color:#4ade80">?page=1&limit=20&sort=name</code></span>
                        </li>
                    </ul>
                </div>
            </div>

            <div class="tab-row">
                <button class="tab-btn active" onclick="switchTab('ep1', 'request')">Request</button>
                <button class="tab-btn" onclick="switchTab('ep1', 'response')">Response</button>
                <button class="tab-btn" onclick="switchTab('ep1', 'codes')">Status Codes</button>
            </div>

            <div class="tab-content active" id="ep1-request">
                <div class="code-block">
<span class="comment"># ❌ BEFORE — Verb in URL, no filtering support</span>
<span class="method">GET</span> <span class="url">/getUsers</span> HTTP/1.1

<span class="comment"># ✅ AFTER — Clean resource URL with optional query params</span>
<span class="method">GET</span> <span class="url">/users?page=1&limit=20&sort=createdAt&order=desc</span> HTTP/1.1
<span class="header-key">Host:</span> api.example.com
<span class="header-key">Accept:</span> application/json
<span class="header-key">Authorization:</span> Bearer &lt;token&gt;
                </div>
            </div>

            <div class="tab-content" id="ep1-response">
                <div class="code-block">
<span class="comment">// ✅ 200 OK — Paginated user list with metadata</span>
{
  <span class="key">"status"</span>: <span class="string">"success"</span>,
  <span class="key">"data"</span>: {
    <span class="key">"users"</span>: [
      { <span class="key">"id"</span>: <span class="value">1</span>, <span class="key">"name"</span>: <span class="string">"Alice"</span>, <span class="key">"email"</span>: <span class="string">"alice@example.com"</span> },
      { <span class="key">"id"</span>: <span class="value">2</span>, <span class="key">"name"</span>: <span class="string">"Bob"</span>, <span class="key">"email"</span>: <span class="string">"bob@example.com"</span> }
    ],
    <span class="key">"pagination"</span>: {
      <span class="key">"page"</span>: <span class="value">1</span>,
      <span class="key">"limit"</span>: <span class="value">20</span>,
      <span class="key">"total"</span>: <span class="value">84</span>,
      <span class="key">"totalPages"</span>: <span class="value">5</span>,
      <span class="key">"hasNext"</span>: <span class="value">true</span>
    }
  }
}
                </div>
            </div>

            <div class="tab-content" id="ep1-codes">
                <div class="info-box">
                    <div class="box-title blue">🔢 Status Codes</div>
                    <div class="status-codes">
                        <span class="status-chip s2xx">200 OK — Users returned successfully</span>
                        <span class="status-chip s4xx">400 Bad Request — Invalid query params</span>
                        <span class="status-chip s4xx">401 Unauthorized — Missing/invalid token</span>
                        <span class="status-chip s4xx">403 Forbidden — Insufficient permissions</span>
                        <span class="status-chip s5xx">500 Internal Server Error — Unexpected failure</span>
                    </div>
                </div>
            </div>
        </div>
    </div>
</div>

