        .section-title {
            font-size: 1.2rem;
            color: #fff;
            margin: 2rem 0 1rem;
            padding-bottom: 0.5rem;
            border-bottom: 1px solid #30363d;
            display: flex;
            align-items: center;
            gap: 0.5rem;
        }

        /* Tabs */
        .tabs {
            display: flex;
            gap: 0.25rem;
            margin-bottom: 1.5rem;
            background: #161b22;
            border: 1px solid #30363d;
            border-radius: 8px;
            padding: 0.3rem;
        }

        .tab-btn {
            flex: 1;
            padding: 0.6rem 1rem;
            background: transparent;
            border: none;
            color: #8b949e;
            cursor: pointer;
            border-radius: 6px;
            font-size: 0.9rem;
            font-weight: 500;
            transition: all 0.2s;
        }

        .tab-btn.active {
            background: #21262d;
            color: #fff;
        }

        .tab-btn:hover:not(.active) {
            color: #c9d1d9;
        }

        .tab-content {
            display: none;
        }

        .tab-content.active {
            display: block;
        }

        /* Endpoint Cards */
        .endpoint-card {
            background: #161b22;
            border: 1px solid #30363d;
            border-radius: 12px;
            margin-bottom: 1.5rem;
            overflow: hidden;
            transition: border-color 0.2s;
