        }

        .copy-btn.copied {
            color: #48bb78;
            border-color: #48bb78;
        }

        .expand-all-btn {
            background: transparent;
            border: 1px solid #2d3748;
            color: #a0aec0;
            border-radius: 8px;
            padding: 0.5rem 1.25rem;
            font-size: 0.85rem;
            cursor: pointer;
            transition: all 0.2s;
            margin-left: auto;
        }

        .expand-all-btn:hover {
            background: #2d3748;
            color: #e2e8f0;
        }

        .progress-bar-wrap {
