        const chevron = document.getElementById('chevron-' + index);
        const isOpen = body.classList.contains('open');
        body.classList.toggle('open', !isOpen);
        chevron.classList.toggle('open', !isOpen);
    }

    function toggleAll() {
        allExpanded = !allExpanded;
        for (let i = 0; i < totalCards; i++) {
            const body = document.getElementById('body-' + i);
            const chevron = document.getElementById('chevron-' + i);
            const card = document.getElementById('card-' + i);
            if (card.style.display !== 'none') {
                body.classList.toggle('open', allExpanded);
                chevron.classList.toggle('open', allExpanded);
            }
        }
        document.getElementById('expand-all-btn').textContent = allExpanded ? 'Collapse All' : 'Expand All';
    }

    function filterCards(severity) {
        // Update button states
        document.querySelectorAll('.filter-btn').forEach(btn => {
            btn.classList.remove('active', 'active-critical', 'active-major', 'active-minor');
        });

        const btn = document.getElementById('btn-' + severity);
        if (severity === 'all') {
            btn.classList.add('active');
        } else if (severity === 'critical') {
            btn.classList.add('active-critical');
        } else if (severity === 'major') {
            btn.classList.add('active-major');
        } else if (severity === 'minor') {
            btn.classList.add('active-minor');
        }

        // Show/hide cards
        for (let i = 0; i < totalCards; i++) {
            const card = document.getElementById('card-' + i);
            if (severity === 'all') {
                card.style.display = '';
            } else {
                const severities = card.dataset.severities.split(',');
                card.style.display = severities.includes(severity) ? '' : 'none';
            }
        }
    }

    // Copy button functionality
    document.querySelectorAll('.copy-btn').forEach(btn => {
        btn.addEventListener('click', (e) => {
            e.stopPropagation();
            const text = btn.dataset.copy;
            navigator.clipboard.writeText(text).then(() => {
                btn.textContent = '✓ Copied';
                btn.classList.add('copied');
                setTimeout(() => {
                    btn.textContent = 'Copy';
                    btn.classList.remove('copied');
                }, 2000);
            });
        });
    });
</script>

