  .json-null   { color: #64748b; }
  .json-punct  { color: #94a3b8; }

  .response-tabs {
    display: flex;
    gap: 0.5rem;
    margin-bottom: 0.8rem;
    flex-wrap: wrap;
  }

  .resp-tab {
    font-size: 0.75rem;
    font-weight: 600;
    padding: 0.3rem 0.8rem;
    border-radius: 6px;
    border: 1px solid #334155;
    background: #0f1117;
    color: #64748b;
    cursor: pointer;
    transition: all 0.15s;
    font-family: 'Courier New', monospace;
  }

  .resp-tab:hover { border-color: #475569; color: #94a3b8; }
  .resp-tab.active-200 { background: #064e3b; color: #34d399; border-color: #065f46; }
  .resp-tab.active-201 { background: #1e3a5f; color: #60a5fa; border-color: #1d4ed8; }
  .resp-tab.active-400 { background: #451a03; color: #fb923c; border-color: #92400e; }
  .resp-tab.active-404 { background: #451a03; color: #fb923c; border-color: #92400e; }
  .resp-tab.active-204 { background: #1e293b; color: #94a3b8; border-color: #475569; }

  .resp-content { display: none; }
  .resp-content.active { display: block; }

  .divider {
    height: 1px;
    background: #334155;
    margin: 1.5rem 0;
  }

  .try-it {
    margin-top: 1.2rem;
  }

  .try-it-header {
    display: flex;
    align-items: center;
    justify-content: space-between;
    margin-bottom: 0.8rem;
  }

  .try-btn {
    font-size: 0.78rem;
    font-weight: 600;
    padding: 0.4rem 1rem;
    border-radius: 6px;
    border: 1px solid #334155;
    background: #263348;
    color: #94a3b8;
    cursor: pointer;
    transition: all 0.15s;
  }

  .try-btn:hover {
    background: #334155;
    color: #e2e8f0;
  }

  .try-inputs {
    display: none;
    flex-direction: column;
    gap: 0.6rem;
    margin-bottom: 0.8rem;
  }

  .try-inputs.visible { display: flex; }

  .try-input-row {
    display: flex;
    align-items: center;
    gap: 0.8rem;
  }

  .try-input-label {
    font-family: 'Courier New', monospace;
    font-size: 0.78rem;
    color: #fbbf24;
    min-width: 80px;
  }

  .try-input-field {
    flex: 1;
    background: #0f1117;
    border: 1px solid #334155;
    border-radius: 6px;
    padding: 0.4rem 0.7rem;
    color: #e2e8f0;
    font-family: 'Courier New', monospace;
    font-size: 0.82rem;
    outline: none;
    transition: border-color 0.15s;
  }

  .try-input-field:focus { border-color: #475569; }

  .send-btn {
    font-size: 0.78rem;
    font-weight: 700;
    padding: 0.4rem 1.2rem;
    border-radius: 6px;
    border: none;
    background: #1d4ed8;
    color: #fff;
    cursor: pointer;
    transition: background 0.15s;
    align-self: flex-start;
  }

  .send-btn:hover { background: #2563eb; }

  .mock-response {
    display: none;
    margin-top: 0.8rem;
  }

  .mock-response.visible { display: block; }

  .mock-status {
    font-size: 0.75rem;
    font-weight: 700;
    margin-bottom: 0.5rem;
    font-family: 'Courier New', monospace;
  }

  .status-ok  { color: #34d399; }
  .status-err { color: #f87171; }
</style>
</head>
<body>

<header>
  <h1>Users API</h1>
  <p>RESTful API — corrected from broken conventions</p>
  <span class="base-url">https://api.example.com/v1</span>
</header>

<div class="container">

  <p class="section-title">User Endpoints</p>

  <!-- ═══════════════════════════════════════════════
       1. GET /users
  ════════════════════════════════════════════════ -->
  <div class="endpoint-card" id="card-1">
    <div class="endpoint-header" onclick="toggle('card-1')">
      <span class="method-badge GET">GET</span>
      <span class="endpoint-path">/users</span>
      <span class="endpoint-summary">List all users</span>
      <span class="chevron">▼</span>
    </div>
    <div class="endpoint-body">

      <div class="fix-banner">
        <span class="fix-label">🔧 Fix Applied</span>
        <span class="before">GET /getUsers</span>
        <span class="arrow">→</span>
        <span class="after">GET /users</span>
        <p class="fix-reason">URLs identify <strong>resources</strong>, not actions. The HTTP method (GET) already communicates the action. Verbs in URLs are redundant and violate REST constraints.</p>
      </div>

      <div class="body-grid">
        <div>
          <p class="sub-title">Query Parameters</p>
          <table class="params-table">
            <tr><th>Name</th><th>Type</th><th></th><th>Description</th></tr>
            <tr>
              <td class="param-name">page</td>
              <td class="param-type">integer</td>
              <td><span class="optional-badge">optional</span></td>
              <td>Page number (default: 1)</td>
            </tr>
            <tr>
              <td class="param-name">limit</td>
              <td class="param-type">integer</td>
              <td><span class="optional-badge">optional</span></td>
              <td>Results per page (default: 20)</td>
            </tr>
          </table>
        </div>
        <div>
          <p class="sub-title">Response Codes</p>
          <div class="response-tabs">
            <button class="resp-tab active-200" onclick="switchTab('r1','200',this)">200</button>
          </div>
          <div id="r1-200" class="resp-content active">
            <div class="code-block"><span class="json-punct">{</span>
  <span class="json-key">"data"</span><span class="json-punct">: [</span>
    <span class="json-punct">{</span>
      <span class="json-key">"id"</span><span class="json-punct">:</span> <span class="json-num">1</span><span class="json-punct">,</span>
      <span class="json-key">"name"</span><span class="json-punct">:</span> <span class="json-str">"Alice"</span><span class="json-punct">,</span>
      <span class="json-key">"email"</span><span class="json-punct">:</span> <span class="json-str">"alice@example.com"</span>
    <span class="json-punct">}</span>
  <span class="json-punct">],</span>
  <span class="json-key">"total"</span><span class="json-punct">:</span> <span class="json-num">42</span><span class="json-punct">,</span>
  <span class="json-key">"page"</span><span class="json-punct">:</span>  <span class="json-num">1</span>
<span class="json-punct">}</span></div>
          </div>
        </div>
      </div>

      <div class="divider"></div>
      <div class="try-it">
        <div class="try-it-header">
          <p class="sub-title" style="margin:0">Try it out</p>
          <button class="try-btn" onclick="toggleTry('try-1')">▶ Open</button>
        </div>
        <div class="try-inputs" id="try-1">
          <div class="try-input-row">
            <span class="try-input-label">page</span>
            <input class="try-input-field" id="t1-page" type="number" value="1" min="1">
          </div>
          <div class="try-input-row">
            <span class="try-input-label">limit</span>
            <input class="try-input-field" id="t1-limit" type="number" value="20" min="1">
          </div>
          <button class="send-btn" onclick="mockSend('mock-1','200')">Send Request</button>
        </div>
        <div class="mock-response" id="mock-1">
          <p class="mock-status status-ok">● 200 OK — 43ms</p>
          <div class="code-block"><span class="json-punct">{</span>
  <span class="json-key">"data"</span><span class="json-punct">: [</span>
    <span class="json-punct">{</span> <span class="json-key">"id"</span><span class="json-punct">:</span> <span class="json-num">1</span><span class="json-punct">,</span> <span class="json-key">"name"</span><span class="json-punct">:</span> <span class="json-str">"Alice"</span><span class="json-punct">,</span> <span class="json-key">"email"</span><span class="json-punct">:</span> <span class="json-str">"alice@example.com"</span> <span class="json-punct">},</span>
    <span class="json-punct">{</span> <span class="json-key">"id"</span><span class="json-punct">:</span> <span class="json-num">2</span><span class="json-punct">,</span> <span class="json-key">"name"</span><span class="json-punct">:</span> <span class="json-str">"Bob"</span><span class="json-punct">,</span>   <span class="json-key">"email"</span><span class="json-punct">:</span> <span class="json-str">"bob@example.com"</span>   <span class="json-punct">}</span>
  <span class="json-punct">],</span>
  <span class="json-key">"total"</span><span class="json-punct">:</span> <span class="json-num">42</span><span class="json-punct">,</span>
  <span class="json-key">"page"</span><span class="json-punct">:</span>  <span class="json-num">1</span>
<span class="json-punct">}</span></div>
        </div>
      </div>

    </div>
  </div>

  <!-- ═══════════════════════════════════════════════
       2. POST /users
  ════════════════════════════════════════════════ -->
  <div class="endpoint-card" id="card-2">
    <div class="endpoint-header" onclick="toggle('card-2')">
      <span class="method-badge POST">POST</span>
      <span class="endpoint-path">/users</span>
      <span class="endpoint-summary">Create a user</span>
      <span class="chevron">▼</span>
    </div>
    <div class="endpoint-body">

      <div class="fix-banner">
        <span class="fix-label">🔧 Fix Applied</span>
        <span class="before">GET /createUser?name=Jo</span>
        <span class="arrow">→</span>
        <span class="after">POST /users</span>
        <p class="fix-reason">GET requests must be <strong>safe and idempotent</strong> — they must never mutate state. Creating a resource requires POST. Data belongs in the request body, not query parameters, to avoid accidental logging of sensitive fields and URL length limits.</p>
      </div>

      <div class="body-grid">
        <div>
          <p class="sub-title">Request Body</p>
          <table class="params-table">
            <tr><th>Field</th><th>Type</th><th></th><th>Description</th></tr>
            <tr>
              <td class="param-name">name</td>
              <td class="param-type">string</td>
              <td><span class="required-badge">required</span></td>
              <td>Full name</td>
            </tr>
            <tr>
              <td class="param-name">email</td>
              <td class="param-type">string</td>
              <td><span class="required-badge">required</span></td>
              <td>Email address</td>
            </tr>
            <tr>
              <td class="param-name">role</td>
              <td class="param-type">string</td>
              <td><span class="optional-badge">optional</span></td>
              <td>user | admin (default: user)</td>
            </tr>
          </table>
        </div>
        <div>
          <p class="sub-title">Response Codes</p>
          <div class="response-tabs">
            <button class="resp-tab active-201" onclick="switchTab('r2','201',this)">201</button>
            <button class="resp-tab" onclick="switchTab('r2','400',this)">400</button>
          </div>
          <div id="r2-201" class="resp-content active">
            <div class="code-block"><span class="json-punct">{</span>
  <span class="json-key">"id"</span><span class="json-punct">:</span>    <span class="json-num">43</span><span class="json-punct">,</span>
  <span class="json-key">"name"</span><span class="json-punct">:</span>  <span class="json-str">"Jo"</span><span class="json-punct">,</span>
  <span class="json-key">"email"</span><span class="json-punct">:</span> <span class="json-str">"jo@example.com"</span><span class="json-punct">,</span>
  <span class="json-key">"role"</span><span class="json-punct">:</span>  <span class="json-str">"user"</span>
<span class="json-punct">}</span></div>
          </div>
          <div id="r2-400" class="resp-content">
            <div class="code-block"><span class="json-punct">{</span>
  <span class="json-key">"error"</span><span class="json-punct">:</span> <span class="json-str">"Validation failed"</span><span class="json-punct">,</span>
  <span class="json-key">"fields"</span><span class="json-punct">: {</span>
    <span class="json-key">"email"</span><span class="json-punct">:</span> <span class="json-str">"Invalid format"</span>
  <span class="json-punct">}</span>
<span class="json-punct">}</span></div>
          </div>
        </div>
      </div>

      <div class="divider"></div>
      <div class="try-it">
        <div class="try-it-header">
          <p class="sub-title" style="margin:0">Try it out</p>
          <button class="try-btn" onclick="toggleTry('try-2')">▶ Open</button>
        </div>
        <div class="try-inputs" id="try-2">
          <div class="try-input-row">
            <span class="try-input-label">name</span>
            <input class="try-input-field" id="t2-name" type="text" placeholder="Jo">
          </div>
          <div class="try-input-row">
            <span class="try-input-label">email</span>
            <input class="try-input-field" id="t2-email" type="text" placeholder="jo@example.com">
          </div>
          <button class="send-btn" onclick="mockSend('mock-2','201')">Send Request</button>
        </div>
        <div class="mock-response" id="mock-2">
          <p class="mock-status status-ok">● 201 Created — 87ms</p>
          <div class="code-block"><span class="json-punct">{</span>
  <span class="json-key">"id"</span><span class="json-punct">:</span>    <span class="json-num">43</span><span class="json-punct">,</span>
  <span class="json-key">"name"</span><span class="json-punct">:</span>  <span class="json-str">"Jo"</span><span class="json-punct">,</span>
  <span class="json-key">"email"</span><span class="json-punct">:</span> <span class="json-str">"jo@example.com"</span><span class="json-punct">,</span>
  <span class="json-key">"role"</span><span class="json-punct">:</span>  <span class="json-str">"user"</span>
<span class="json-punct">}</span></div>
        </div>
      </div>

    </div>
  </div>

  <!-- ═══════════════════════════════════════════════
       3. PUT /users/{id}
  ════════════════════════════════════════════════ -->
  <div class="endpoint-card" id="card-3">
    <div class="endpoint-header" onclick="toggle('card-3')">
      <span class="method-badge PUT">PUT</span>
      <span class="endpoint-path">/users/<span class="param">{id}</span></span>
      <span class="endpoint-summary">Replace a user</span>
      <span class="chevron">▼</span>
    </div>
    <div class="endpoint-body">

      <div class="fix-banner">
        <span class="fix-label">🔧 Fix Applied</span>
        <span class="before">PUT /updateAllUsers</span>
        <span class="arrow">→</span>
        <span class="after">PUT /users/{id}</span>
        <p class="fix-reason">PUT is idempotent and targets a <strong>specific resource</strong>. Without an ID you cannot safely replace one record. The verb "update" is redundant — PUT's semantics already mean full replacement. Use <code style="color:#c084fc">PATCH /users/{id}</code> if you only need partial updates.</p>
      </div>

      <div class="body-grid">
        <div>
          <p class="sub-title">Path Parameters</p>
          <table class="params-table">
            <tr><th>Name</th><th>Type</th><th></th><th>Description</th></tr>
            <tr>
              <td class="param-name">id</td>
              <td class="param-type">integer</td>
              <td><span class="required-badge">required</span></td>
              <td>User ID</td>
            </tr>
          </table>
          <br>
          <p class="sub-title">Request Body</p>
          <table class="params-table">
            <tr><th>Field</th><th>Type</th><th></th><th>Description</th></tr>
            <tr>
              <td class="param-name">name</td>
              <td class="param-type">string</td>
              <td><span class="required-badge">required</span></td>
              <td>Full name</td>
            </tr>
            <tr>
              <td class="param-name">email</td>
              <td class="param-type">string</td>
              <td><span class="required-badge">required</span></td>
              <td>Email address</td>
            </tr>
          </table>
        </div>
        <div>
          <p class="sub-title">Response Codes</p>
          <div class="response-tabs">
            <button class="resp-tab active-200" onclick="switchTab('r3','200',this)">200</button>
            <button class="resp-tab" onclick="switchTab('r3','404',this)">404</button>
          </div>
          <div id="r3-200" class="resp-content active">
            <div class="code-block"><span class="json-punct">{</span>
  <span class="json-key">"id"</span><span class="json-punct">:</span>    <span class="json-num">5</span><span class="json-punct">,</span>
  <span class="json-key">"name"</span><span class="json-punct">:</span>  <span class="json-str">"Alice Updated"</span><span class="json-punct">,</span>
  <span class="json-key">"email"</span><span class="json-punct">:</span> <span class="json-str">"alice2@example.com"</span>
<span class="json-punct">}</span></div>
          </div>
          <div id="r3-404" class="resp-content">
            <div class="code-block"><span class="json-punct">{</span>
  <span class="json-key">"error"</span><span class="json-punct">:</span> <span class="json-str">"User not found"</span>
<span class="json-punct">}</span></div>
          </div>
        </div>
      </div>

      <div class="divider"></div>
      <div class="try-it">
        <div class="try-it-header">
          <p class="sub-title" style="margin:0">Try it out</p>
          <button class="try-btn" onclick="toggleTry('try-3')">▶ Open</button>
        </div>
        <div class="try-inputs" id="try-3">
          <div class="try-input-row">
            <span class="try-input-label">id</span>
            <input class="try-input-field" id="t3-id" type="number" placeholder="5">
          </div>
          <div class="try-input-row">
            <span class="try-input-label">name</span>
            <input class="try-input-field" id="t3-name" type="text" placeholder="Alice Updated">
          </div>
          <div class="try-input-row">
            <span class="try-input-label">email</span>
            <input class="try-input-field" id="t3-email" type="text" placeholder="alice2@example.com">
          </div>
          <button class="send-btn" onclick="mockSend('mock-3','200')">Send Request</button>
        </div>
        <div class="mock-response" id="mock-3">
          <p class="mock-status status-ok">● 200 OK — 61ms</p>
          <div class="code-block"><span class="json-punct">{</span>
  <span class="json-key">"id"</span><span class="json-punct">:</span>    <span class="json-num">5</span><span class="json-punct">,</span>
  <span class="json-key">"name"</span><span class="json-punct">:</span>  <span class="json-str">"Alice Updated"</span><span class="json-punct">,</span>
  <span class="json-key">"email"</span><span class="json-punct">:</span> <span class="json-str">"alice2@example.com"</span>
<span class="json-punct">}</span></div>
        </div>
      </div>

    </div>
  </div>

  <!-- ═══════════════════════════════════════════════
       4. DELETE /users/{id}
  ════════════════════════════════════════════════ -->
  <div class="endpoint-card" id="card-4">
    <div class="endpoint-header" onclick="toggle('card-4')">
      <span class="method-badge DELETE">DELETE</span>
      <span class="endpoint-path">/users/<span class="param">{id}</span></span>
      <span class="endpoint-summary">Delete a user</span>
      <span class="chevron">▼</span>
    </div>
    <div class="endpoint-body">

      <div class="fix-banner">
        <span class="fix-label">🔧 Fix Applied</span>
        <span class="before">POST /user/delete/5</span>
        <span class="arrow">→</span>
        <span class="after">DELETE /users/{id}</span>
        <p class="fix-reason">HTTP has a <strong>DELETE method for exactly this purpose</strong>. Using POST to delete tunnels intent through the URL ("delete/5"), breaking uniform interface. DELETE is also idempotent — calling it twice on the same resource is safe. Note: plural <code style="color:#7dd3fc">/users</code> for consistency with the collection resource.</p>
      </div>

      <div class="body-grid">
        <div>
          <p class="sub-title">Path Parameters</p>
          <table class="params-table">
            <tr><th>Name</th><th>Type</th><th></th><th>Description</th></tr>
            <tr>
              <td class="param-name">id</td>
              <td class="param-type">integer</td>
              <td><span class="required-badge">required</span></td>
              <td>User ID to delete</td>
            </tr>
          </table>
        </div>
        <div>
          <p class="sub-title">Response Codes</p>
          <div class="response-tabs">
            <button class="resp-tab active-204" onclick="switchTab('r4','204',this)">204</button>
            <button class="resp-tab" onclick="switchTab('r4','404',this)">404</button>
          </div>
          <div id="r4-204" class="resp-content active">
            <div class="code-block" style="color:#64748b; font-style:italic">// 204 No Content
// Empty response body</div>
          </div>
          <div id="r4-404" class="resp-content">
            <div class="code-block"><span class="json-punct">{</span>
  <span class="json-key">"error"</span><span class="json-punct">:</span> <span class="json-str">"User not found"</span>
<span class="json-punct">}</span></div>
          </div>
        </div>
      </div>

      <div class="divider"></div>
      <div class="try-it">
        <div class="try-it-header">
          <p class="sub-title" style="margin:0">Try it out</p>
          <button class="try-btn" onclick="toggleTry('try-4')">▶ Open</button>
        </div>
        <div class="try-inputs" id="try-4">
          <div class="try-input-row">
            <span class="try-input-label">id</span>
            <input class="try-input-field" id="t4-id" type="number" placeholder="5">
          </div>
          <button class="send-btn" onclick="mockSend('mock-4','204')">Send Request</button>
        </div>
        <div class="mock-response" id="mock-4">
          <p class="mock-status status-ok">● 204 No Content — 38ms</p>
          <div class="code-block" style="color:#64748b; font-style:italic">// Empty response body</div>
        </div>
      </div>

    </div>
  </div>

  <!-- ═══════════════════════════════════════════════
       Bonus: PATCH /users/{id}
  ════════════════════════════════════════════════ -->
  <div class="endpoint-card" id="card-5">
    <div class="endpoint-header" onclick="toggle('card-5')">
      <span class="method-badge PATCH">PATCH</span>
      <span class="endpoint-path">/users/<span class="param">{id}</span></span>
      <span class="endpoint-summary">Partial update</span>
      <span class="chevron">▼</span>
    </div>
    <div class="endpoint-body">

      <div class="fix-banner" style="background:#1a1a2e; border-color:#6b21a8;">
        <span class="fix-label" style="color:#c084fc;">✦ Bonus Endpoint</span>
        <p class="fix-reason">Since the original API only had PUT, PATCH is added here to demonstrate the distinction: <strong>PUT replaces the entire resource</strong> (all fields required), while <strong>PATCH applies a partial update</strong> (only send fields you want to change). This is a common real-world requirement.</p>
