<script>
  function toggle(id) {
    const card = document.getElementById(id);
    card.classList.toggle('open');
  }

  function toggleTry(id) {
    const el = document.getElementById(id);
    el.classList.toggle('visible');
    const btn = el.previousElementSibling.querySelector('.try-btn');
    btn.textContent = el.classList.contains('visible') ? '▼ Close' : '▶ Open';
  }

  function mockSend(mockId, code) {
    const el = document.getElementById(mockId);
    el.classList.remove('visible');
    // small delay for realism
    setTimeout(() => el.classList.add('visible'), 320);
  }

  function switchTab(prefix, code, btn) {
    // hide all content panels for this prefix
    document.querySelectorAll(`[id^="${prefix}-"]`).forEach(el => {
      el.classList.remove('active');
    });
    // deactivate all tab buttons in same group
    btn.closest('.response-tabs').querySelectorAll('.resp-tab').forEach(b => {
      b.className = 'resp-tab';
    });
    // activate selected
    const panel = document.getElementById(`${prefix}-${code}`);
    if (panel) panel.classList.add('active');
    btn.classList.add(`active-${code}`);
  }
</script>

